import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Robust JSON parser that extracts JSON from within a string, 
 * handling common LLM artifacts like markdown code blocks.
 */
const extractAndParseJson = <T>(text: string): T => {
  try {
    // 1. Clean markdown code blocks
    let cleaned = text.replace(/```json\s?/g, '').replace(/```\s?/g, '').trim();

    // 2. Find the first '{' and last '}'
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');

    if (start === -1 || end === -1) {
      return JSON.parse(cleaned) as T;
    }

    cleaned = cleaned.substring(start, end + 1);

    // 3. Basic cleanup for problematic characters often found in AI responses
    // We handle newlines explicitly because JSON.parse requires \n to be escaped as \\n in strings
    // but the .text property from Gemini usually returns literal newlines.
    return JSON.parse(cleaned) as T;
  } catch (error) {
    console.error("JSON Extraction/Parsing failed:", error, "Raw text:", text);
    throw new Error("Could not parse the AI response as valid JSON.");
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Text to process:
      ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A 2-3 bullet point summary of the content." },
            simplifiedText: { type: Type.STRING, description: "The simplified, easier-to-read version of the text." }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No response from Gemini");

    return JSON.parse(jsonText) as SimplifiedContentResponse;
  } catch (error) {
    console.error("Gemini Simplification Error:", error);
    return {
      summary: "Simplification Unavailable",
      simplifiedText: "I'm sorry, I couldn't simplify this content right now."
    };
  }
};

export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are simulating a web browser. The user is searching for: "${query}".

      1. Use the googleSearch tool to find relevant up-to-date info.
      2. Construct a modern, accessible web page response based on findings.
      3. **CRITICAL**: Your entire response MUST be a SINGLE VALID JSON object.
      4. DO NOT use markdown code blocks.
      5. The 'contentHtml' must use Tailwind CSS classes with SINGLE QUOTES (e.g., class='p-4') to avoid JSON escapes.
      6. Required JSON structure:
      {
        "title": "Page Title",
        "category": "Topic Category",
        "author": "Author or Brand",
        "date": "Current Date",
        "mainImageKeyword": "one search term",
        "contentHtml": "<div class='space-y-4'>... responsive HTML content ...</div>",
        "sidebarItems": [{"title": "...", "snippet": "..."}],
        "relatedLinks": ["..."]
      }

      Design requirements for contentHtml:
      - Modern spacing using 'space-y-6' or 'gap-4'.
      - High contrast friendly colors.
      - Responsive design: MUST use md: and lg: prefixes for layouts.
      - Use cards with 'bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700'.`,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No response from Gemini");

    const data = extractAndParseJson<WebPageContent>(jsonText);

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sourceUrls = chunks
        .map((c: any) => c.web?.uri)
        .filter((u: string | undefined): u is string => !!u);

    data.relatedLinks = [...new Set([...(data.relatedLinks || []), ...sourceUrls])];

    return {
      title: data.title || "Untitled Page",
      category: data.category || "General",
      author: data.author || "Web Publisher",
      date: data.date || new Date().toLocaleDateString(),
      mainImageKeyword: data.mainImageKeyword || "website",
      contentHtml: data.contentHtml || "<p>No content generated.</p>",
      sidebarItems: data.sidebarItems || [],
      relatedLinks: data.relatedLinks || []
    };

  } catch (error) {
    console.error("Gemini Generation Error:", error);
    return {
      title: "Navigation Error",
      category: "System",
      author: "Browser Engine",
      date: new Date().toLocaleDateString(),
      mainImageKeyword: "error",
      contentHtml: `
        <div class='p-8 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-3xl text-center'>
          <h2 class='text-2xl font-bold text-red-800 dark:text-red-400 mb-4'>Page Generation Failed</h2>
          <p class='text-red-600 dark:text-red-300 mb-4'>We encountered an error while trying to build this page. This might be due to a technical limitation or search failure.</p>
          <div class='text-left bg-white dark:bg-slate-900 p-4 rounded-xl border dark:border-slate-700 font-mono text-xs opacity-60 overflow-auto max-h-32'>
            ${error instanceof Error ? error.message : "Unknown error"}
          </div>
          <button onclick='window.location.reload()' class='mt-8 px-8 py-3 bg-red-600 text-white rounded-full font-bold shadow-lg hover:bg-red-700 transition-colors'>
            Try Refreshing
          </button>
        </div>
      `,
      sidebarItems: [],
      relatedLinks: []
    };
  }
};

import React, { useState, useEffect } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent } from './types';
import { simplifyContent, generatePageContent } from './services/geminiService';

const App: React.FC = () => {
  // Initial Settings
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);

  // Dynamic Web Content State
  const [isLoadingPage, setIsLoadingPage] = useState(false);

  // Navigation History
  const [history, setHistory] = useState<WebPageContent[]>([]);

  const welcomePage: WebPageContent = {
    title: "AccessiWeb Browser",
    category: "Welcome",
    author: "System",
    date: new Date().toLocaleDateString(),
    mainImageKeyword: "Technology",
    contentHtml: "", 
    sidebarItems: [],
    relatedLinks: []
  };

  const [pageContent, setPageContent] = useState<WebPageContent>(welcomePage);

  // Helper to update settings
  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };

      if (newSettings.mode) {
        switch (newSettings.mode) {
          case 'dyslexia':
            next.fontFamily = '"Comic Sans MS", "Chalkboard SE", sans-serif';
            next.lineSpacing = 2.0;
            next.readingRuler = true;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            break;
          case 'high-contrast':
            next.fontSize = 20;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'reading':
            next.fontFamily = 'Georgia, serif';
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            break;
          case 'default':
            next.fontFamily = 'Inter, system-ui, sans-serif';
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.readingRuler = false;
            next.highlightLinks = false;
            next.stopAnimations = false;
            next.hideSidebar = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      const articleText = document.getElementById('main-article')?.innerText;
      if (articleText) {
        const utterance = new SpeechSynthesisUtterance(articleText);
        utterance.onend = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
      }
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) {
        setSimplifiedContent(null);
        return;
    }

    setIsSimplifying(true);
    const articleText = document.getElementById('main-article')?.innerText || "";
    const textToProcess = articleText.substring(0, 5000); 

    const result = await simplifyContent(textToProcess);
    setSimplifiedContent(result);
    setIsSimplifying(false);
  };

  const handleNavigate = async (query: string) => {
    if (!query.trim()) return;

    if (pageContent.category !== 'Welcome') {
       setHistory(prev => [...prev, pageContent]);
    }

    if (query.toLowerCase() === "home" || query.toLowerCase() === "accessiweb browser") {
      setPageContent(welcomePage);
      setSimplifiedContent(null);
      return;
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);

    try {
      const content = await generatePageContent(query);
      setPageContent(content);
    } catch (err) {
      console.error("Navigation error:", err);
    } finally {
      setIsLoadingPage(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (history.length === 0) return;
    const previousPage = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setPageContent(previousPage);
    setSimplifiedContent(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    return () => window.speechSynthesis.cancel();
  }, []);

  return (
    <div className="relative font-sans text-slate-900 bg-gray-50 dark:bg-slate-950 min-h-screen overflow-x-hidden">
      <ControlPanel 
        settings={settings}
        updateSettings={updateSettings}
        onSpeak={handleSpeak}
        isSpeaking={isSpeaking}
        onSimplify={handleSimplify}
        isSimplifying={isSimplifying}
      />

      <SimulatedPage 
        settings={settings} 
        simplifiedContent={simplifiedContent}
        content={pageContent}
        onNavigate={handleNavigate}
        onBack={handleBack}
        canGoBack={history.length > 0}
        isLoading={isLoadingPage}
      />

      <div className="fixed bottom-4 left-4 bg-white/90 dark:bg-slate-800/90 backdrop-blur border border-slate-200 dark:border-slate-700 p-3 rounded-lg shadow-lg text-xs max-w-xs z-50 pointer-events-none opacity-50 hover:opacity-100 transition-opacity">
        <p className="font-semibold text-indigo-600 dark:text-indigo-400">Extension Simulator</p>
        <p className="text-slate-500 dark:text-slate-400">
          Search "World History" or "Vegan Recipes" to test.
        </p>
      </div>
    </div>
  );
};

export default App;

