    };
  }
};

/**
 * Generates page content. Falls back to creative simulation if Search Tool fails (quota issues).
 */
export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  const prompt = `You are a browser engine simulating a website for the search: "${query}".
    Return a SINGLE VALID JSON object representing the page.
    Use Tailwind CSS classes with SINGLE QUOTES in 'contentHtml'.
    Design: Modern, high-contrast, responsive (use md: grid-cols-2 etc).

    Required JSON structure:
    {
      "title": "Page Title",
      "category": "Topic",
      "author": "Publisher",
      "date": "${new Date().toLocaleDateString()}",
      "mainImageKeyword": "visual keyword",
      "contentHtml": "<div class='space-y-6'>... HTML content ...</div>",
      "sidebarItems": [{"title": "...", "snippet": "..."}],
      "relatedLinks": ["URL1", "URL2"]
    }`;

  try {
    // Attempt 1: With Google Search (Best Quality)
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const data = extractAndParseJson<WebPageContent>(response.text || "");
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sourceUrls = chunks
        .map((c: any) => c.web?.uri)
        .filter((u: string | undefined): u is string => !!u);

    data.relatedLinks = [...new Set([...(data.relatedLinks || []), ...sourceUrls])];
    return data;

  } catch (error: any) {
    console.warn("Search-grounded generation failed (likely quota). Falling back to creative mode...", error.message);

    // Attempt 2: Without Search Tools (Bypass Quota/Search Restrictions)
    try {
      const fallbackResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt + "\n\nNote: Search tools are unavailable, use your internal knowledge to simulate a realistic page.",
      });

      const data = extractAndParseJson<WebPageContent>(fallbackResponse.text || "");
      // Indicate this is a simulation
      data.author = data.author + " (Simulated)";
      return data;

    } catch (fallbackError) {
      console.error("Critical Generation Failure:", fallbackError);
      throw fallbackError;
    }
  }
};

