import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Robustly extracts and parses JSON from a string that might contain 
 * markdown code blocks or additional text.
 */
const extractAndParseJson = <T>(text: string): T => {
  try {
    let cleaned = text
      .replace(/```json/gi, "")
      .replace(/```/g, "")
      .trim();

    const start = cleaned.indexOf("{");
    const end = cleaned.lastIndexOf("}");

    if (start === -1 || end === -1) {
      throw new Error("No valid JSON object boundaries found in response.");
    }

    cleaned = cleaned.substring(start, end + 1);
    return JSON.parse(cleaned) as T;
  } catch (error) {
    console.error("JSON Extraction failed. Raw text snippet:", text.substring(0, 100));
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Text to process:
      ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A 2-3 bullet point summary." },
            simplifiedText: { type: Type.STRING, description: "The simplified text." }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as SimplifiedContentResponse;
  } catch (error) {
    console.error("Simplification Error:", error);
    return {
      summary: "Simplification unavailable.",
      simplifiedText: "The simplification service is currently busy. Please try again in a moment."
    };
  }
};

/**
 * Generates page content. Focused on replicating the ACTUAL UI structure of the site requested.
 */
export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  const prompt = `You are a Layout Reconstructor. The user is searching for: "${query}".
    Your goal is to REPLICATE the specific structure of the likely website for this query.
    - If it's a technical query like W3Schools, include a left-side navigation look, code examples in grey boxes, and green buttons.
    - If it's a news site, include headlines and multiple columns.

    Return a SINGLE VALID JSON object.
    Use Tailwind CSS classes with SINGLE QUOTES in 'contentHtml'.
    DO NOT include any external links or images in the HTML.

    Required JSON structure:
    {
      "title": "Page Title",
      "category": "Topic Category",
      "author": "Publisher Name",
      "date": "${new Date().toLocaleDateString()}",
      "contentHtml": "<div class='flex flex-col md:flex-row gap-6'>... Realistically Structured HTML ...</div>",
      "sidebarItems": [{"title": "Quick Fact", "snippet": "..."}]
    }

    Content requirements:
    - Use code blocks: '<pre class="bg-slate-100 p-4 rounded-lg overflow-x-auto text-sm"><code>...</code></pre>'
    - Use tables for documentation.
    - Use structured side-navigation inside the contentHtml if appropriate.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const data = extractAndParseJson<WebPageContent>(response.text || "");
    return {
      ...data,
      title: data.title || query,
      author: data.author || "Web Source"
    };

  } catch (error: any) {
    console.warn("Search-grounded generation failed. Falling back to simulation...", error.message);

    try {
      const fallbackResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt + "\n\nNote: Use your internal knowledge to simulate the layout.",
      });

      return extractAndParseJson<WebPageContent>(fallbackResponse.text || "");
    } catch (fallbackError) {
      console.error("Critical Generation Failure:", fallbackError);
      throw fallbackError;
    }
  }
};

