import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent } from './types';
import { simplifyContent, generatePageContent } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [history, setHistory] = useState<WebPageContent[]>([]);

  const pageCache = useRef<Map<string, WebPageContent>>(new Map());

  const welcomePage: WebPageContent = {
    title: "AccessiMod",
    category: "Welcome",
    author: "System",
    date: new Date().toLocaleDateString(),
    contentHtml: "", 
    sidebarItems: []
  };

  const [pageContent, setPageContent] = useState<WebPageContent>(welcomePage);

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        switch (newSettings.mode) {
          case 'dyslexia':
            next.fontFamily = '"Comic Sans MS", "Chalkboard SE", sans-serif';
            next.lineSpacing = 2.0;
            next.readingRuler = true;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            break;
          case 'high-contrast':
            next.fontSize = 20;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'reading':
            next.fontFamily = 'Georgia, serif';
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            break;
          case 'default':
            next.fontFamily = 'Inter, system-ui, sans-serif';
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.readingRuler = false;
            next.highlightLinks = false;
            next.stopAnimations = false;
            next.hideSidebar = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      const articleText = document.getElementById('main-article')?.innerText;
      if (articleText) {
        const utterance = new SpeechSynthesisUtterance(articleText);
        utterance.onend = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
      }
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) {
        setSimplifiedContent(null);
        return;
    }
    setIsSimplifying(true);
    const articleText = document.getElementById('main-article')?.innerText || "";
    const result = await simplifyContent(articleText.substring(0, 3000));
    setSimplifiedContent(result);
    setIsSimplifying(false);
  };

  const handleNavigate = async (query: string) => {
    if (!query.trim()) return;
    const normalizedQuery = query.toLowerCase().trim();

    if (normalizedQuery === "home" || normalizedQuery === "accessimod") {
      setPageContent(welcomePage);
      setSimplifiedContent(null);
      return;
    }

    if (pageContent.category !== 'Welcome') {
       setHistory(prev => [...prev, pageContent]);
    }

    if (pageCache.current.has(normalizedQuery)) {
      setPageContent(pageCache.current.get(normalizedQuery)!);
      setSimplifiedContent(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);

    try {
      const content = await generatePageContent(query);
      setPageContent(content);
      pageCache.current.set(normalizedQuery, content);
    } catch (err) {
      console.error("Navigation error:", err);
      setPageContent({
        title: "Navigation Error",
        category: "System",
        author: "Error Handler",
        date: new Date().toLocaleDateString(),
        contentHtml: "<div class='p-10 text-center bg-white dark:bg-slate-800 rounded-2xl'><h2 class='text-2xl font-bold mb-4'>Connection Failed</h2><p>The simulator could not reach the requested site. Please try a different query.</p></div>",
        sidebarItems: []
      });
    } finally {
      setIsLoadingPage(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (history.length === 0) return;
    const previousPage = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setPageContent(previousPage);
    setSimplifiedContent(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    return () => window.speechSynthesis.cancel();
  }, []);

  return (
    <div className="relative font-sans text-slate-900 bg-gray-50 dark:bg-slate-950 min-h-screen overflow-x-hidden">
      <ControlPanel 
        settings={settings}
        updateSettings={updateSettings}
        onSpeak={handleSpeak}
        isSpeaking={isSpeaking}
        onSimplify={handleSimplify}
        isSimplifying={isSimplifying}
      />

      <SimulatedPage 
        settings={settings} 
        simplifiedContent={simplifiedContent}
        content={pageContent}
        onNavigate={handleNavigate}
        onBack={handleBack}
        canGoBack={history.length > 0}
        isLoading={isLoadingPage}
      />

      <div className="fixed bottom-4 left-4 bg-white/90 dark:bg-slate-800/90 backdrop-blur border border-slate-200 dark:border-slate-700 p-3 rounded-lg shadow-lg text-xs z-50 pointer-events-none opacity-50 hover:opacity-100 transition-opacity">
        <p className="font-semibold text-indigo-600 dark:text-indigo-400">AccessiMod Engine</p>
        <p className="text-slate-500 dark:text-slate-400">
          Clean Site Simulation Active
        </p>
      </div>
    </div>
  );
};

export default App;

export type AccessibilityMode = 'default' | 'dyslexia' | 'adhd' | 'high-contrast' | 'reading';

export interface AccessibilitySettings {
  mode: AccessibilityMode;
  fontSize: number; // Base pixel size (default 16)
  fontWeight: number; // 100-900 (default 400)
  lineSpacing: number; // Multiplier (default 1.5)
  letterSpacing: number; // px (default 0)
  fontFamily: string;
  showImages: boolean;
  highlightLinks: boolean;
  readingRuler: boolean; // For ADHD/Dyslexia tracking
  stopAnimations: boolean; // ADHD reduced motion
  hideSidebar: boolean; // ADHD distraction removal
}

export interface SimplifiedContentResponse {
  summary: string;
  simplifiedText: string;
}

export interface WebPageContent {
  title: string;
  contentHtml: string; // The full page layout in HTML format
}

import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Robustly extracts and parses JSON from a string that might contain 
 * markdown code blocks or additional text.
 */
const extractAndParseJson = <T>(text: string): T => {
  try {
    let cleaned = text
      .replace(/```json/gi, "")
      .replace(/```/g, "")
      .trim();

    const start = cleaned.indexOf("{");
    const end = cleaned.lastIndexOf("}");

    if (start === -1 || end === -1) {
      throw new Error("No valid JSON object boundaries found in response.");
    }

    cleaned = cleaned.substring(start, end + 1);
    return JSON.parse(cleaned) as T;
  } catch (error) {
    console.error("JSON Extraction failed. Raw text snippet:", text.substring(0, 100));
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Text to process:
      ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A 2-3 bullet point summary." },
            simplifiedText: { type: Type.STRING, description: "The simplified text." }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as SimplifiedContentResponse;
  } catch (error) {
    console.error("Simplification Error:", error);
    return {
      summary: "Simplification unavailable.",
      simplifiedText: "The simplification service is currently busy. Please try again in a moment."
    };
  }
};

/**
 * Generates page content. Focused on replicating the ACTUAL UI structure of the site requested.
 */
export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  const prompt = `You are a Website Reconstructor. The user wants to visit: "${query}".
    Your task is to REPLICATE the specific layout, navigation, and content of that website.

    CRITICAL RULES:
    1. DO NOT include any <img> tags.
    2. DO NOT include any external <a> links (keep href='#' or internal paths).
    3. REPLICATE THE SPECIFIC UI: 
       - If it is W3Schools: include a LEFT sidebar navigation with a vertical list of links (e.g., HTML Home, HTML Intro), a central content area, green 'Try it Yourself' buttons, and light grey background boxes for code.
       - If it is Wikipedia: include a left sidebar, a right-side info box (infobox), and a white background with thin borders.
    4. Use Tailwind CSS classes with SINGLE QUOTES in 'contentHtml'.

    Return a SINGLE VALID JSON object:
    {
      "title": "Actual Page Title",
      "contentHtml": "<div class='flex min-h-screen bg-white'>... Replicated Sidebar and Content ...</div>"
    }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const data = extractAndParseJson<WebPageContent>(response.text || "");
    return {
      title: data.title || query,
      contentHtml: data.contentHtml || "<div class='p-8'>No content could be replicated.</div>"
    };

  } catch (error: any) {
    console.warn("Search-grounded generation failed. Falling back to simulation...", error.message);

    try {
      const fallbackResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt + "\n\nNote: Use your internal knowledge to simulate the layout as search tools are restricted.",
      });

      return extractAndParseJson<WebPageContent>(fallbackResponse.text || "");
    } catch (fallbackError) {
      console.error("Critical Generation Failure:", fallbackError);
      throw fallbackError;
    }
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent } from '../types';
import { Search, ArrowLeft, ArrowRight, RotateCw, Lock, Home, Zap } from 'lucide-react';

interface SimulatedPageProps {
  settings: AccessibilitySettings;
  simplifiedContent: SimplifiedContentResponse | null;
  content: WebPageContent;
  onNavigate: (query: string) => void;
  onBack: () => void;
  canGoBack: boolean;
  isLoading: boolean;
}

const SimulatedPage: React.FC<SimulatedPageProps> = ({ 
  settings, 
  simplifiedContent, 
  content,
  onNavigate,
  onBack,
  canGoBack,
  isLoading
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mouseY, setMouseY] = useState(0);
  const [urlInput, setUrlInput] = useState('');
  const [homeSearchInput, setHomeSearchInput] = useState('');

  useEffect(() => {
    if (content) {
      if (content.title === 'AccessiMod') {
        setUrlInput('https://accessimod.io/start');
      } else {
        const slug = content.title.toLowerCase().replace(/[^a-z0-9]+/g, '-');
        setUrlInput(`https://www.web-reader.com/${slug}`);
      }
    }
  }, [content]);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => setMouseY(e.clientY);
    if (settings.readingRuler) window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [settings.readingRuler]);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onNavigate(urlInput);
  };

  const handleHomeSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onNavigate(homeSearchInput);
  };

  const styleVars = {
    '--bg-color': settings.mode === 'high-contrast' ? '#000000' : 
                  settings.mode === 'reading' ? '#fdf6e3' : '#ffffff',
    '--text-color': settings.mode === 'high-contrast' ? '#ffff00' : 
                    settings.mode === 'reading' ? '#2e2e2e' : '#1f2937',
    '--font-size': `${settings.fontSize}px`,
    '--font-weight': settings.fontWeight,
    '--line-height': `${settings.lineSpacing}`,
    '--letter-spacing': settings.mode === 'dyslexia' ? '0.05em' : 'normal',
    '--font-family': settings.mode === 'dyslexia' 
      ? '"Comic Sans MS", "Chalkboard SE", sans-serif' 
      : settings.fontFamily,
  } as React.CSSProperties;

  const isDistractionFree = settings.mode === 'adhd' || settings.mode === 'reading' || settings.hideSidebar;
  const isHome = content.title === 'AccessiMod';

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-slate-900 transition-colors duration-300">

