        {settings.stopAnimations && `*, *::before, *::after { animation: none !important; transition: none !important; }`}
        {settings.highlightLinks && `
          a, button.nav-link {
            background-color: ${settings.mode === 'high-contrast' ? '#000' : '#ffeb3b'} !important;
            color: ${settings.mode === 'high-contrast' ? '#fff' : '#000'} !important;
            border: 2px solid ${settings.mode === 'high-contrast' ? '#fff' : '#000'} !important;
            padding: 0 4px !important; font-weight: bold !important;
