          <button className="hidden sm:block p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded" onClick={() => onNavigate(urlInput)}><RotateCw size={16} /></button>
        </div>
        <form onSubmit={handleSearchSubmit} className="flex-1">
          <div className="relative group">
            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"><Lock size={12} /></div>
            <input type="text" value={urlInput} onChange={(e) => setUrlInput(e.target.value)} placeholder="Search or type URL..." className="w-full bg-slate-100 dark:bg-slate-900 text-slate-700 dark:text-slate-300 text-sm py-2 pl-8 pr-10 rounded-full focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-transparent" />
            <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 p-1 bg-indigo-600 text-white rounded-full hover:bg-indigo-700"><Search size={12} /></button>
