      </div>

      <div ref={containerRef} className="flex-1 transition-all duration-300 relative" style={{ backgroundColor: styleVars['--bg-color'], color: styleVars['--text-color'], fontFamily: styleVars['--font-family'], lineHeight: styleVars['--line-height'], fontWeight: styleVars['--font-weight'] }}>
        {isLoading && (
          <div className="absolute inset-0 z-50 flex items-center justify-center bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm">
            <div className="flex flex-col items-center gap-4">
              <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
