                        <button type="submit" className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-full font-bold shadow-md flex items-center gap-2"><Search size={20} />Go</button>
                      </div>
                    </form>
                  </div>
               </div>
            </div>
          </div>
        ) : (
          <div className="w-full">
            {simplifiedContent && (
              <div className={`m-4 p-6 rounded-xl border-2 border-dashed max-w-4xl mx-auto ${settings.mode === 'high-contrast' ? 'border-yellow-400' : 'border-indigo-200 bg-indigo-50/30'}`}>
                <h3 className="font-bold text-lg mb-2 flex items-center gap-2 text-indigo-600"><Zap size={20} /> Focus Summary</h3>
                <div dangerouslySetInnerHTML={{__html: simplifiedContent.summary.replace(/\n/g, '<br/>')}} className="mb-4 text-sm" />
                <p className="border-t border-indigo-100 dark:border-indigo-900/50 pt-4 text-base">{simplifiedContent.simplifiedText}</p>
              </div>
            )}

            <div className="w-full overflow-x-hidden">
              {/* The contentHtml now contains the full replicated UI (including sidebars if needed) */}
              <main className="w-full" id="main-article">
                <div className="max-w-none" dangerouslySetInnerHTML={{ __html: content.contentHtml }} />
              </main>
            </div>
          </div>
        )}
      </div>
    </div>
  );
