import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent } from './types';
import { simplifyContent, generatePageContent } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [history, setHistory] = useState<WebPageContent[]>([]);

  const pageCache = useRef<Map<string, WebPageContent>>(new Map());

  const welcomePage: WebPageContent = {
    title: "AccessiMod",
    contentHtml: "", 
  };

  const [pageContent, setPageContent] = useState<WebPageContent>(welcomePage);

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        switch (newSettings.mode) {
          case 'dyslexia':
            next.fontFamily = 'Inter, system-ui, sans-serif'; // Often sans is better, but can use specialized fonts if loaded
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontWeight = 500;
            next.letterSpacing = 0.5;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'reading':
            next.fontFamily = 'Georgia, serif';
            next.lineSpacing = 2.0;
            next.fontSize = 22;
            next.hideSidebar = true;
            break;
          case 'default':
            next.fontFamily = 'Inter, system-ui, sans-serif';
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.readingRuler = false;
            next.highlightLinks = false;
            next.stopAnimations = false;
            next.hideSidebar = false;
            next.letterSpacing = 0;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      const articleText = document.getElementById('main-article')?.innerText;
      if (articleText) {
        const utterance = new SpeechSynthesisUtterance(articleText);
        utterance.rate = 0.95; // Slightly slower for better comprehension
        utterance.pitch = 1;
        utterance.onend = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
      }
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) {
        setSimplifiedContent(null);
        return;
    }
    setIsSimplifying(true);
    const articleText = document.getElementById('main-article')?.innerText || "";
    // Grab enough text for a good summary but not so much it hits limits
    const result = await simplifyContent(articleText.substring(0, 4000));
    setSimplifiedContent(result);
    setIsSimplifying(false);
  };

  const handleNavigate = async (query: string) => {
    if (!query.trim()) return;
    const normalizedQuery = query.toLowerCase().trim();

    if (normalizedQuery === "home" || normalizedQuery === "accessimod") {
      setPageContent(welcomePage);
      setSimplifiedContent(null);
      return;
    }

    if (pageContent.title !== 'AccessiMod') {
       setHistory(prev => [...prev, pageContent]);
    }

    if (pageCache.current.has(normalizedQuery)) {
      setPageContent(pageCache.current.get(normalizedQuery)!);
      setSimplifiedContent(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);

    try {
      const content = await generatePageContent(query);
      setPageContent(content);
      pageCache.current.set(normalizedQuery, content);
    } catch (err) {
      console.error("Navigation error:", err);
      setPageContent({
        title: "Simulation Offline",
        contentHtml: `
          <div class='flex flex-col items-center justify-center min-h-[60vh] p-10 text-center'>
            <div class='w-20 h-20 bg-red-50 text-red-500 rounded-3xl flex items-center justify-center mb-6'>
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
            </div>
            <h2 class='text-3xl font-black mb-4'>AccessiMod Connection Limit</h2>
            <p class='text-slate-500 max-w-md'>The simulation engine is temporarily at capacity. Please try again in a moment or search a different topic.</p>
            <button onclick='window.location.reload()' class='mt-8 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all'>Reset Simulator</button>
          </div>
        `,
      });
    } finally {
      setIsLoadingPage(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (history.length === 0) return;
    const previousPage = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setPageContent(previousPage);
    setSimplifiedContent(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    return () => window.speechSynthesis.cancel();
  }, []);

  return (
    <div className="relative font-sans text-slate-900 bg-white dark:bg-[#0b0f19] min-h-screen overflow-x-hidden antialiased">
      <ControlPanel 
        settings={settings}
        updateSettings={updateSettings}
        onSpeak={handleSpeak}
        isSpeaking={isSpeaking}
        onSimplify={handleSimplify}
        isSimplifying={isSimplifying}
      />

      <SimulatedPage 
        settings={settings} 
        simplifiedContent={simplifiedContent}
        content={pageContent}
        onNavigate={handleNavigate}
        onBack={handleBack}
        canGoBack={history.length > 0}
        isLoading={isLoadingPage}
      />

      {/* Modern Status Pill */}
      <div className="fixed bottom-6 left-6 z-50 pointer-events-none transition-all duration-500 group-hover:opacity-100 opacity-60">
        <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border border-black/5 dark:border-white/5 pl-4 pr-5 py-2.5 rounded-full shadow-2xl flex items-center gap-3">
          <div className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse" />
          <div className="flex flex-col">
             <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest leading-none">AccessiMod Engine</span>
             <span className="text-[9px] text-slate-400 font-bold tracking-tighter mt-0.5">V1.4 • ACTIVE SIMULATION</span>
          </div>
        </div>
      </div>
    </div>
  );
};

