import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Robustly extracts and parses JSON from a string that might contain 
 * markdown code blocks or additional text.
 */
const extractAndParseJson = <T>(text: string): T => {
  try {
    let cleaned = text
      .replace(/```json/gi, "")
      .replace(/```/g, "")
      .trim();

    const start = cleaned.indexOf("{");
    const end = cleaned.lastIndexOf("}");

    if (start === -1 || end === -1) {
      throw new Error("No valid JSON object boundaries found in response.");
    }

    cleaned = cleaned.substring(start, end + 1);
    return JSON.parse(cleaned) as T;
  } catch (error) {
    console.error("JSON Extraction failed. Raw text snippet:", text.substring(0, 100));
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Text to process:
      ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A 2-3 bullet point summary." },
            simplifiedText: { type: Type.STRING, description: "The simplified text." }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as SimplifiedContentResponse;
  } catch (error) {
    console.error("Simplification Error:", error);
    return {
      summary: "Simplification unavailable.",
      simplifiedText: "The simplification service is currently busy. Please try again in a moment."
    };
  }
};

/**
 * Generates page content based on deep analysis of the target website.
 * No longer replicates the UI, but extracts and presents information semantically.
 */
export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  const prompt = `You are an Intelligent Content Architect. The user is searching for: "${query}".

    TASK: 
    1. Use Google Search to find the actual content from the most relevant source for "${query}".
    2. ANALYZE the full website information and EXTRACT only the core informative content.
    3. DISCARD navigation menus, sidebars, headers, and extraneous UI elements.
    4. ORGANIZE the information into a professional, high-fidelity technical document.

    STYLE GUIDELINES:
    - Use clean Tailwind CSS classes (SINGLE QUOTES).
    - Format code with: <pre class='bg-slate-900 text-slate-100 p-6 rounded-2xl my-6 overflow-x-auto border border-white/10 shadow-xl'><code class='text-sm font-mono'>...</code></pre>
    - Use technical callouts: <div class='bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500 p-6 my-8 rounded-r-2xl'>...</div>
    - Focus on semantic hierarchy (h1, h2, h3).
    - ABSOLUTELY NO <img> TAGS.
    - ABSOLUTELY NO EXTERNAL <a> LINKS.

    JSON STRUCTURE:
    {
      "title": "Clear Technical Title",
      "contentHtml": "<article class='max-w-4xl mx-auto'>... High Quality Content ...</article>"
    }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1, // Keep it factual and consistent
      }
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => 
      chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null
    ).filter(Boolean) || [];

    const data = extractAndParseJson<WebPageContent>(response.text || "");
    return {
      title: data.title || query,
      contentHtml: data.contentHtml || "<div class='p-8'>Content analysis failed.</div>",
      sources
    };

  } catch (error: any) {
    console.warn("Search-grounded analysis failed. Falling back to internal simulation...", error.message);

    try {
      const fallbackResponse = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: prompt + "\n\nNote: Analyze your internal knowledge of this topic to produce the content.",
      });

      return extractAndParseJson<WebPageContent>(fallbackResponse.text || "");
    } catch (fallbackError) {
      console.error("Critical Analysis Failure:", fallbackError);
      throw fallbackError;
    }
  }
};

