  ChevronRight,
  Sparkles,
  Brain
} from 'lucide-react';

interface ControlPanelProps {
  settings: AccessibilitySettings;
  updateSettings: (newSettings: Partial<AccessibilitySettings>) => void;
  onSpeak: () => void;
  isSpeaking: boolean;
  onSimplify: () => void;
  isSimplifying: boolean;
  onGenerateQuiz: () => void;
  isGeneratingQuiz: boolean;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  settings, 
  updateSettings, 
  onSpeak, 
  isSpeaking,
  onSimplify,
  isSimplifying,
  onGenerateQuiz,
  isGeneratingQuiz
}) => {
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: window.innerWidth > 640 ? window.innerWidth - 360 : 10, y: 80 });
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number }>({ startX: 0, startY: 0, initialX: 0, initialY: 0 });

  const modes: { id: AccessibilityMode; label: string; icon: React.ReactNode; desc: string }[] = [
    { id: 'default', label: 'Default', icon: <Monitor size={16} />, desc: 'Standard web view' },
    { id: 'dyslexia', label: 'Dyslexia', icon: <Type size={16} />, desc: 'Enhanced legibility' },
    { id: 'adhd', label: 'ADHD', icon: <Zap size={16} />, desc: 'Minimized distractions' },
    { id: 'high-contrast', label: 'Contrast', icon: <Sun size={16} />, desc: 'High visibility' },
    { id: 'reading', label: 'Reader', icon: <BookOpen size={16} />, desc: 'Pure content focus' },
  ];

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: position.x,
      initialY: position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragRef.current.startX;
      const dy = e.clientY - dragRef.current.startY;
      setPosition({
        x: Math.max(10, Math.min(window.innerWidth - 330, dragRef.current.initialX + dx)),
        y: Math.max(10, Math.min(window.innerHeight - 100, dragRef.current.initialY + dy))
      });
    };
    const handleMouseUp = () => setIsDragging(false);
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  if (isMinimized) {
    return (
      <button 
        onClick={() => setIsMinimized(false)}
        style={{ top: position.y, left: position.x + (window.innerWidth < 640 ? 0 : 280) }}
        className="fixed z-50 bg-indigo-600/90 hover:bg-indigo-600 backdrop-blur-xl text-white p-4 rounded-full shadow-lg transition-all active:scale-95 border border-white/20 group"
      >
        <Settings2 size={24} className="group-hover:rotate-45 transition-transform" />
      </button>
    );
  }

  return (
    <div 
      style={{ top: position.y, left: position.x }}
      className={`fixed w-[calc(100vw-2rem)] sm:w-[320px] bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl rounded-3xl shadow-2xl border border-white/30 dark:border-slate-700/50 overflow-hidden z-50 flex flex-col max-h-[85vh] transition-all duration-300 ${isDragging ? 'scale-[1.02] rotate-1' : ''}`}
    >
      <div onMouseDown={handleMouseDown} className="px-5 py-4 flex justify-between items-center cursor-grab active:cursor-grabbing bg-gradient-to-r from-indigo-600 to-violet-600 text-white">
        <div className="flex items-center gap-3">
          <Sparkles size={16} />
          <h2 className="font-bold text-base tracking-tight">AccessiMod</h2>
        </div>
        <button onClick={() => setIsMinimized(true)} className="p-1.5 rounded-full hover:bg-white/20">
          <X size={18} />
        </button>
      </div>

      <div className="overflow-y-auto p-5 space-y-7 custom-scrollbar">
        <section>
          <h3 className="text-[10px] font-bold text-slate-400 uppercase mb-4 tracking-widest">Experience Mode</h3>
          <div className="grid grid-cols-5 gap-2">
            {modes.map((m) => (
              <button
                key={m.id}
                onClick={() => updateSettings({ mode: m.id })}
                className={`flex flex-col items-center gap-2 p-2 rounded-xl transition-all ${
                  settings.mode === m.id
                    ? 'bg-indigo-600 text-white shadow-lg'
                    : 'bg-slate-50 dark:bg-slate-800 text-slate-500'
                }`}
              >
                <div className="p-1.5">{m.icon}</div>
                <span className="text-[9px] font-bold truncate">{m.label}</span>
              </button>
            ))}
          </div>
        </section>

        <section className="bg-slate-50/50 dark:bg-slate-800/30 p-4 rounded-2xl space-y-5">
          <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Typography</h3>
          <div className="space-y-3">
            <input type="range" min="14" max="32" value={settings.fontSize} onChange={(e) => updateSettings({ fontSize: Number(e.target.value) })} className="w-full accent-indigo-600" />
            <div className="grid grid-cols-2 gap-4">
               <select value={settings.fontWeight} onChange={(e) => updateSettings({ fontWeight: Number(e.target.value) })} className="w-full bg-white dark:bg-slate-800 text-xs py-2 rounded-lg">
                  <option value="400">Regular</option>
                  <option value="700">Bold</option>
               </select>
               <select value={settings.lineSpacing} onChange={(e) => updateSettings({ lineSpacing: Number(e.target.value) })} className="w-full bg-white dark:bg-slate-800 text-xs py-2 rounded-lg">
                  <option value="1.6">Normal</option>
                  <option value="2.0">Loose</option>
               </select>
            </div>
          </div>
        </section>

        <section className="space-y-3">
          <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Assistant</h3>
          <button onClick={onSimplify} disabled={isSimplifying} className="w-full bg-gradient-to-r from-indigo-500 to-purple-600 text-white p-3 rounded-xl flex items-center justify-between shadow-lg">
            <span className="text-xs font-bold">{isSimplifying ? 'Analyzing...' : 'AI Focus Reconstruct'}</span>
            <Zap size={14} />
          </button>

          <button onClick={onGenerateQuiz} disabled={isGeneratingQuiz} className="w-full bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border p-3 rounded-xl flex items-center justify-between shadow-sm hover:border-indigo-500 transition-all">
            <span className="text-xs font-bold">{isGeneratingQuiz ? 'Brainstorming...' : 'Generate Brain Quiz'}</span>
            <Brain size={16} />
          </button>

          <button onClick={onSpeak} className={`w-full p-3 rounded-xl border flex items-center justify-between ${isSpeaking ? 'bg-green-500 text-white' : 'bg-white dark:bg-slate-800'}`}>
            <span className="text-xs font-bold">Text-to-Speech</span>
            <Volume2 size={16} />
          </button>
        </section>
      </div>
    </div>
  );
