            <div id="article-content" className="prose prose-slate prose-lg max-w-none dark:prose-invert" dangerouslySetInnerHTML={{ __html: content.contentHtml }} />

            {quiz && quiz.length > 0 && (
              <div className="mt-20 p-10 bg-slate-50 dark:bg-slate-900/50 rounded-[2.5rem] border">
                <h3 className="text-2xl font-black mb-8 flex items-center gap-3 text-indigo-600"><ShieldCheck /> Knowledge Check</h3>
                <div className="space-y-10">
                  {quiz.map((q, idx) => (
                    <div key={idx} className="space-y-4">
                      <p className="font-bold text-xl">{idx + 1}. {q.question}</p>
                      <div className="grid gap-3">
                        {q.options.map((opt, oIdx) => {
                          const isSelected = quizAnswers[idx] === oIdx;
                          const isCorrect = oIdx === q.correctAnswerIndex;
                          const showFeedback = quizAnswers[idx] !== undefined;

                          let btnClass = "p-4 rounded-xl border text-left transition-all flex items-center justify-between ";
                          if (showFeedback) {
                            if (isCorrect) btnClass += "bg-green-100 border-green-500 text-green-800";
                            else if (isSelected) btnClass += "bg-red-100 border-red-500 text-red-800";
                            else btnClass += "bg-white opacity-50";
                          } else {
                            btnClass += "bg-white hover:border-indigo-500";
                          }

                          return (
                            <button key={oIdx} onClick={() => !showFeedback && setQuizAnswers(prev => ({...prev, [idx]: oIdx}))} className={btnClass}>
                              <span>{opt}</span>
                              {showFeedback && isCorrect && <CheckCircle2 size={18} />}
                              {showFeedback && isSelected && !isCorrect && <XCircle size={18} />}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SimulatedPage;

import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion } from './types';
import { simplifyContent, generatePageContent, generateQuiz } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });

  const pageCache = useRef<Map<string, WebPageContent>>(new Map());

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        switch (newSettings.mode) {
          case 'dyslexia':
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.readingRuler = true;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'default':
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.readingRuler = false;
            next.highlightLinks = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      const articleText = document.getElementById('article-content')?.innerText;
      if (articleText) {
        const utterance = new SpeechSynthesisUtterance(articleText);
        utterance.onend = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
      }
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { setSimplifiedContent(null); return; }
    setIsSimplifying(true);
    const text = document.getElementById('article-content')?.innerText || "";
    const result = await simplifyContent(text.substring(0, 4000));
    setSimplifiedContent(result);
    setIsSimplifying(false);
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { setQuiz(null); return; }
    setIsGeneratingQuiz(true);
    const text = document.getElementById('article-content')?.innerText || "";
    const questions = await generateQuiz(text);
    setQuiz(questions);
    setIsGeneratingQuiz(false);
  };

  const handleNavigate = async (query: string) => {
    if (!query.trim() || query === "Home") {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      setSimplifiedContent(null);
      setQuiz(null);
      return;
    }

    if (pageContent.title !== 'AccessiMod') setHistory(prev => [...prev, pageContent]);
    setIsLoadingPage(true);
    setSimplifiedContent(null);
    setQuiz(null);

    try {
      const content = await generatePageContent(query);
      setPageContent(content);
    } catch (err) {
      setPageContent({ title: "Error", contentHtml: "<p>Failed to retrieve content.</p>" });
    } finally {
      setIsLoadingPage(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <div className="relative bg-white dark:bg-[#0b0f19] min-h-screen selection:bg-indigo-500 selection:text-white">
      <ControlPanel 
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={() => history.length > 0 && setPageContent(history.pop()!)}
        canGoBack={history.length > 0} isLoading={isLoadingPage}
        quiz={quiz}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion } from './types';
import { simplifyContent, generatePageContent, generateQuiz } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });

  const pageCache = useRef<Map<string, WebPageContent>>(new Map());

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        switch (newSettings.mode) {
          case 'dyslexia':
            next.lineSpacing = 1.8;
            next.fontWeight = 500;
            // ruler removed from auto-activation
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            // ruler removed from auto-activation
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'default':
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.highlightLinks = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      // Find visible text either in simplified view or main content
      const simplifiedText = document.getElementById('ai-summary-content')?.innerText;
      const mainText = document.getElementById('article-content')?.innerText;
      const textToRead = simplifiedText ? `${simplifiedText}. Main content follows: ${mainText}` : mainText;

      if (textToRead) {
        const utterance = new SpeechSynthesisUtterance(textToRead);
        utterance.onend = () => setIsSpeaking(false);
        utterance.onerror = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
      }
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { 
      setSimplifiedContent(null); 
      return; 
    }
    const text = document.getElementById('article-content')?.innerText || "";
    if (!text.trim()) return;

    setIsSimplifying(true);
    const result = await simplifyContent(text.substring(0, 4000));
    setSimplifiedContent(result);
    setIsSimplifying(false);
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { 
      setQuiz(null); 
      return; 
    }
    const text = document.getElementById('article-content')?.innerText || "";
    if (!text.trim()) return;

    setIsGeneratingQuiz(true);
    const questions = await generateQuiz(text);
    setQuiz(questions);
    setIsGeneratingQuiz(false);
  };

  const handleNavigate = async (query: string) => {
    if (!query.trim() || query === "Home" || query.toLowerCase() === "accessimod") {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      setSimplifiedContent(null);
      setQuiz(null);
      return;
    }

    if (pageContent.title !== 'AccessiMod') {
      setHistory(prev => [...prev, pageContent]);
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);
    setQuiz(null);

    try {
      const content = await generatePageContent(query);
      setPageContent(content);
    } catch (err) {
      setPageContent({ title: "Error", contentHtml: "<article class='p-10 text-center'><h1 class='text-2xl font-bold'>System Analysis Failed</h1><p>We couldn't analyze the requested content. Please try a different topic.</p></article>" });
    } finally {
      setIsLoadingPage(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleBack = () => {
    if (history.length === 0) return;
    const newHistory = [...history];
    const previousPage = newHistory.pop();
    if (previousPage) {
      setHistory(newHistory);
      setPageContent(previousPage);
      setSimplifiedContent(null);
      setQuiz(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const isHome = pageContent.title === 'AccessiMod';

  return (
    <div className="relative bg-white dark:bg-[#0b0f19] min-h-screen selection:bg-indigo-500 selection:text-white">
      <ControlPanel 
        settings={settings} 
        updateSettings={updateSettings}
        onSpeak={handleSpeak} 
        isSpeaking={isSpeaking}
        onSimplify={handleSimplify} 
        isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} 
        isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} 
        simplifiedContent={simplifiedContent}
        content={pageContent} 
        onNavigate={handleNavigate}
        onBack={handleBack}
        canGoBack={history.length > 0} 
        isLoading={isLoadingPage}
        quiz={quiz}
      />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { AccessibilityMode, AccessibilitySettings } from '../types';
import { 
  Type, 
  Zap, 
  BookOpen, 
  Volume2, 
  Settings2, 
  Monitor, 
  Sun,
  X,
  Sparkles,
  Brain,
  MousePointer2
} from 'lucide-react';

interface ControlPanelProps {
  settings: AccessibilitySettings;
  updateSettings: (newSettings: Partial<AccessibilitySettings>) => void;
  onSpeak: () => void;
  isSpeaking: boolean;
  onSimplify: () => void;
  isSimplifying: boolean;
  onGenerateQuiz: () => void;
  isGeneratingQuiz: boolean;
  isHome: boolean;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  settings, 
  updateSettings, 
  onSpeak, 
  isSpeaking,
  onSimplify,
  isSimplifying,
  onGenerateQuiz,
  isGeneratingQuiz,
  isHome
}) => {
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: window.innerWidth > 640 ? window.innerWidth - 360 : 10, y: 80 });
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number }>({ startX: 0, startY: 0, initialX: 0, initialY: 0 });

  const modes: { id: AccessibilityMode; label: string; icon: React.ReactNode; desc: string }[] = [
    { id: 'default', label: 'Default', icon: <Monitor size={16} />, desc: 'Standard web view' },
    { id: 'dyslexia', label: 'Dyslexia', icon: <Type size={16} />, desc: 'Enhanced legibility' },
    { id: 'adhd', label: 'ADHD', icon: <Zap size={16} />, desc: 'Minimized distractions' },
    { id: 'high-contrast', label: 'Contrast', icon: <Sun size={16} />, desc: 'High visibility' },
    { id: 'reading', label: 'Reader', icon: <BookOpen size={16} />, desc: 'Pure content focus' },
  ];

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: position.x,
      initialY: position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragRef.current.startX;
      const dy = e.clientY - dragRef.current.startY;
      setPosition({
        x: Math.max(10, Math.min(window.innerWidth - 330, dragRef.current.initialX + dx)),
        y: Math.max(10, Math.min(window.innerHeight - 100, dragRef.current.initialY + dy))
      });
    };
    const handleMouseUp = () => setIsDragging(false);
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  if (isMinimized) {
    return (
      <button 
        onClick={() => setIsMinimized(false)}
        style={{ top: position.y, left: position.x + (window.innerWidth < 640 ? 0 : 280) }}
        className="fixed z-50 bg-indigo-600 hover:bg-indigo-700 text-white p-4 rounded-full shadow-2xl transition-all active:scale-95 border border-white/20 group"
      >
        <Settings2 size={24} className="group-hover:rotate-45 transition-transform duration-500" />
      </button>
    );
  }

  return (
    <div 
      style={{ top: position.y, left: position.x }}
      className={`fixed w-[calc(100vw-2rem)] sm:w-[320px] bg-white/95 dark:bg-slate-900/95 backdrop-blur-2xl rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.3)] border border-white/30 dark:border-slate-700/50 overflow-hidden z-50 flex flex-col max-h-[85vh] transition-transform duration-200 ${isDragging ? 'scale-[1.02]' : ''}`}
    >
      <div onMouseDown={handleMouseDown} className="px-5 py-4 flex justify-between items-center cursor-grab active:cursor-grabbing bg-gradient-to-r from-indigo-600 to-violet-600 text-white">
        <div className="flex items-center gap-3">
          <Sparkles size={16} />
          <h2 className="font-bold text-sm tracking-tight">AccessiMod Toolkit</h2>
        </div>
        <button onClick={() => setIsMinimized(true)} className="p-1.5 rounded-full hover:bg-white/20 transition-colors">
          <X size={18} />
        </button>
      </div>

      <div className="overflow-y-auto p-5 space-y-7 custom-scrollbar">
        <section>
          <h3 className="text-[10px] font-bold text-slate-400 uppercase mb-4 tracking-widest">Visual Mode</h3>
          <div className="grid grid-cols-5 gap-2">
            {modes.map((m) => (
              <button
                key={m.id}
                onClick={() => updateSettings({ mode: m.id })}
                className={`flex flex-col items-center gap-2 p-2 rounded-xl transition-all ${
                  settings.mode === m.id
                    ? 'bg-indigo-600 text-white shadow-lg'
                    : 'bg-slate-50 dark:bg-slate-800 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700'
                }`}
              >
                <div className="p-1">{m.icon}</div>
                <span className="text-[9px] font-bold truncate w-full text-center">{m.label}</span>
              </button>
            ))}
          </div>
        </section>

        <section className="bg-slate-50/50 dark:bg-slate-800/30 p-4 rounded-2xl space-y-4">
          <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Refinement</h3>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-xs font-bold text-slate-600 dark:text-slate-400">Font Size</span>
              <span className="text-[10px] font-mono bg-white dark:bg-slate-700 px-1.5 py-0.5 rounded">{settings.fontSize}px</span>
            </div>
            <input 
              type="range" min="14" max="36" 
              value={settings.fontSize} 
              onChange={(e) => updateSettings({ fontSize: Number(e.target.value) })} 
              className="w-full accent-indigo-600 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer" 
            />
            <div className="grid grid-cols-2 gap-2">
               <select value={settings.fontWeight} onChange={(e) => updateSettings({ fontWeight: Number(e.target.value) })} className="bg-white dark:bg-slate-800 text-[10px] font-bold py-2 rounded-lg border-none shadow-sm focus:ring-1 ring-indigo-500">
                  <option value="400">Regular Weight</option>
                  <option value="700">Bold Weight</option>
                  <option value="900">Black Weight</option>
               </select>
               <select value={settings.lineSpacing} onChange={(e) => updateSettings({ lineSpacing: Number(e.target.value) })} className="bg-white dark:bg-slate-800 text-[10px] font-bold py-2 rounded-lg border-none shadow-sm focus:ring-1 ring-indigo-500">
                  <option value="1.6">Normal Spacing</option>
                  <option value="2.0">Relaxed Spacing</option>
                  <option value="2.5">Extra Spacing</option>
               </select>
            </div>
          </div>
        </section>

        <section className="space-y-2">
          <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Assistive Tools</h3>

          <button 
            onClick={onSimplify} 
            disabled={isSimplifying || isHome} 
            className={`w-full p-3 rounded-xl flex items-center justify-between transition-all ${
              isHome ? 'opacity-30 cursor-not-allowed bg-slate-100 dark:bg-slate-800' : 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-md active:scale-95'
            }`}
          >
            <div className="flex items-center gap-3">
              <Zap size={16} className={isSimplifying ? 'animate-pulse' : ''} />
              <span className="text-xs font-bold">{isSimplifying ? 'Processing...' : 'AI Smart Focus'}</span>
            </div>
          </button>

          <button 
            onClick={onGenerateQuiz} 
            disabled={isGeneratingQuiz || isHome} 
            className={`w-full p-3 rounded-xl flex items-center justify-between transition-all border ${
              isHome ? 'opacity-30 cursor-not-allowed border-slate-200 dark:border-slate-800' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 hover:border-indigo-500 shadow-sm active:scale-95'
            }`}
          >
            <div className="flex items-center gap-3">
              <Brain size={16} className={isGeneratingQuiz ? 'animate-pulse' : ''} />
              <span className="text-xs font-bold">{isGeneratingQuiz ? 'Brainstorming...' : 'Knowledge Quiz'}</span>
            </div>
          </button>

          <div className="grid grid-cols-2 gap-2 mt-2">
            <button 
              onClick={onSpeak} 
              disabled={isHome}
              className={`p-3 rounded-xl flex flex-col items-center gap-2 transition-all border ${
                isHome ? 'opacity-30 cursor-not-allowed border-slate-200' : 
                isSpeaking ? 'bg-green-500 text-white border-transparent' : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:border-indigo-500 active:scale-95'
              }`}
            >
              <Volume2 size={20} className={isSpeaking ? 'animate-pulse' : ''} />
              <span className="text-[10px] font-bold">Read Aloud</span>
            </button>

            <button 
              onClick={() => updateSettings({ readingRuler: !settings.readingRuler })} 
              className={`p-3 rounded-xl flex flex-col items-center gap-2 transition-all border ${
                settings.readingRuler ? 'bg-amber-500 text-white border-transparent' : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:border-amber-500 active:scale-95'
              }`}
            >
              <MousePointer2 size={20} />
              <span className="text-[10px] font-bold">Focus Ruler</span>
            </button>
          </div>
        </section>
      </div>
    </div>
  );
};

