                  <div className="space-y-12">
                    {quiz.map((q, idx) => (
                      <div key={idx} className="space-y-6">
                        <p className="font-black text-2xl tracking-tight text-slate-900 dark:text-white">{idx + 1}. {q.question}</p>
                        <div className="grid gap-4">
                          {q.options.map((opt, oIdx) => {
                            const isSelected = quizAnswers[idx] === oIdx;
                            const isCorrect = oIdx === q.correctAnswerIndex;
                            const showFeedback = quizAnswers[idx] !== undefined;

                            let btnClass = "p-5 rounded-2xl border-2 text-left transition-all flex items-center justify-between font-bold text-lg ";
                            if (showFeedback) {
