                            }

                            return (
                              <button 
                                key={oIdx} 
                                onClick={() => !showFeedback && setQuizAnswers(prev => ({...prev, [idx]: oIdx}))} 
                                className={btnClass}
                              >
                                <span>{opt}</span>
                                {showFeedback && isCorrect && <CheckCircle2 className="text-green-600" size={24} />}
                                {showFeedback && isSelected && !isCorrect && <XCircle className="text-red-600" size={24} />}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

