                              btnClass += "bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200";
                            }

                            return (
                              <button 
                                key={oIdx} 
                                onClick={() => !showFeedback && setQuizAnswers(prev => ({...prev, [idx]: oIdx}))} 
                                className={btnClass}
                              >
                                <span>{opt}</span>
                                {showFeedback && isCorrect && <CheckCircle2 className="text-green-600" size={24} />}
                                {showFeedback && isSelected && !isCorrect && <XCircle className="text-red-600" size={24} />}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
