import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent, QuizQuestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const extractAndParseJson = <T>(text: string): T => {
  try {
    let cleaned = text
      .replace(/```json/gi, "")
      .replace(/```/g, "")
      .trim();

    const start = cleaned.indexOf("{");
    const end = cleaned.lastIndexOf("}");

    if (start === -1) {
      // Try array
      const startArr = cleaned.indexOf("[");
      const endArr = cleaned.lastIndexOf("]");
      if (startArr !== -1 && endArr !== -1) {
        cleaned = cleaned.substring(startArr, endArr + 1);
        return JSON.parse(cleaned) as T;
      }
      throw new Error("No valid JSON boundaries found.");
    }

    cleaned = cleaned.substring(start, end + 1);
    return JSON.parse(cleaned) as T;
  } catch (error) {
    console.error("JSON Extraction failed:", text.substring(0, 100));
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Text to process:
      ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            simplifiedText: { type: Type.STRING }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });
    // Correctly using .text property from GenerateContentResponse
    return JSON.parse(response.text || "{}") as SimplifiedContentResponse;
  } catch (error) {
    return { summary: "Unavailable.", simplifiedText: "Error processing content." };
  }
};

export const generateQuiz = async (text: string): Promise<QuizQuestion[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Based on the following content, generate a 3-question multiple-choice quiz. 
      Return the output as a JSON array of objects with 'question', 'options' (array of 4), and 'correctAnswerIndex'.

      Content: ${text.substring(0, 5000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswerIndex: { type: Type.INTEGER }
            },
            required: ["question", "options", "correctAnswerIndex"]
          }
        }
      }
    });
    // Correctly using .text property from GenerateContentResponse
    return JSON.parse(response.text || "[]") as QuizQuestion[];
  } catch (error) {
    console.error("Quiz Gen Error:", error);
    return [];
  }
};

export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  const prompt = `You are an Intelligent Content Architect. Search for: "${query}".

    TASK: 
    1. Use Google Search to find the core knowledge for "${query}".
    2. Analyze the full source and EXTRACT only the core informative text.
    3. Remove ALL navigation, sidebars, ads, and UI.
    4. Provide the result in a highly semantic, accessible HTML structure inside an <article>.

    STYLE:
    - Use Tailwind CSS classes with single quotes.
    - Large, clear headers.
    - Distinctive sections with spacing.
    - No <img> or external <a> tags.

    JSON:
    {
      "title": "Title of Information",
      "contentHtml": "<article class='space-y-8'>...</article>"
    }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      }
    });

    // Extract grounding chunks as required by the Search Grounding guidelines
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => {
      if (chunk.web) {
        return {
          title: chunk.web.title || "Information Source",
          uri: chunk.web.uri
        };
      }
      return null;
    }).filter((s: any) => s !== null && s.uri) || [];

    const data = extractAndParseJson<WebPageContent>(response.text || "");
    return {
      title: data.title || query,
      contentHtml: data.contentHtml || "<div class='p-8'>Content not found.</div>",
      sources: sources.length > 0 ? sources : undefined
    };
  } catch (error: any) {
    const fallbackResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt + "\n\nNote: Fallback to internal knowledge.",
    });
    return extractAndParseJson<WebPageContent>(fallbackResponse.text || "");
  }
};

