                      {quiz.map((q, idx) => (
                        <div key={idx} className="space-y-8">
                          <p className="text-2xl font-black text-slate-800 dark:text-white leading-tight">{idx + 1}. {q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => {
                              const isSelected = quizAnswers[idx] === oIdx;
                              const isCorrect = oIdx === q.correctAnswerIndex;
                              const hasAnswered = quizAnswers[idx] !== undefined;

                              return (
                                <button 
                                  key={oIdx} 
                                  disabled={hasAnswered}
                                  onClick={() => setQuizAnswers(prev => ({...prev, [idx]: oIdx}))}
                                  className={`p-6 text-left rounded-3xl border-2 transition-all font-bold text-lg flex items-center justify-between ${
                                    hasAnswered 
                                      ? isCorrect ? 'bg-emerald-50 border-emerald-500 text-emerald-800' : isSelected ? 'bg-rose-50 border-rose-500 text-rose-800' : 'bg-slate-100 dark:bg-slate-900 border-transparent opacity-40'
                                      : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-indigo-500 hover:shadow-xl'
                                  }`}
                                >
                                  <span>{opt}</span>
                                  {hasAnswered && isCorrect && <CheckCircle2 className="text-emerald-500" size={24} />}
                                  {hasAnswered && isSelected && !isCorrect && <XCircle className="text-rose-500" size={24} />}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default SimulatedPage;

import React, { useState, useRef, useEffect } from 'react';
import { AccessibilityMode, AccessibilitySettings } from '../types';
import { 
  Type, 
  Zap, 
  BookOpen, 
  Volume2, 
  Settings2, 
  Monitor, 
  Sun,
  X,
  Sparkles,
  Brain,
  MousePointer2,
  ChevronRight,
  ChevronLeft
} from 'lucide-react';

interface ControlPanelProps {
  settings: AccessibilitySettings;
  updateSettings: (newSettings: Partial<AccessibilitySettings>) => void;
  onSpeak: () => void;
  isSpeaking: boolean;
  onSimplify: () => void;
  isSimplifying: boolean;
  onGenerateQuiz: () => void;
  isGeneratingQuiz: boolean;
  isHome: boolean;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  settings, 
  updateSettings, 
  onSpeak, 
  isSpeaking,
  onSimplify,
  isSimplifying,
  onGenerateQuiz,
  isGeneratingQuiz,
  isHome
}) => {
  const [isOpen, setIsOpen] = useState(true);
  const [position, setPosition] = useState({ x: window.innerWidth - 360, y: 120 });
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number }>({ startX: 0, startY: 0, initialX: 0, initialY: 0 });

  const modes: { id: AccessibilityMode; label: string; icon: React.ReactNode }[] = [
    { id: 'default', label: 'Default', icon: <Monitor size={16} /> },
    { id: 'dyslexia', label: 'Dyslexia', icon: <Type size={16} /> },
    { id: 'adhd', label: 'ADHD', icon: <Zap size={16} /> },
    { id: 'high-contrast', label: 'Contrast', icon: <Sun size={16} /> },
    { id: 'reading', label: 'Reader', icon: <BookOpen size={16} /> },
  ];

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: position.x,
      initialY: position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragRef.current.startX;
      const dy = e.clientY - dragRef.current.startY;
      setPosition({
        x: Math.max(10, Math.min(window.innerWidth - 340, dragRef.current.initialX + dx)),
        y: Math.max(10, Math.min(window.innerHeight - 500, dragRef.current.initialY + dy))
      });
    };
    const handleMouseUp = () => setIsDragging(false);
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-10 right-10 z-50 bg-indigo-600 hover:bg-indigo-700 text-white p-5 rounded-3xl shadow-2xl flex items-center gap-3 active:scale-95 transition-all group"
      >
        <Settings2 size={24} className="group-hover:rotate-90 transition-transform duration-500" />
        <span className="font-bold pr-2">Accessibility Hub</span>
      </button>
    );
  }

  return (
    <div 
      style={{ left: position.x, top: position.y }}
      className={`fixed w-[320px] bg-white/90 dark:bg-slate-900/90 backdrop-blur-2xl rounded-[2.5rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.3)] border border-white/40 dark:border-slate-800/40 z-50 flex flex-col transition-all duration-200 ${isDragging ? 'scale-105 opacity-80 cursor-grabbing' : 'opacity-100 cursor-grab'}`}
      onMouseDown={handleMouseDown}
    >
      <div className="p-6 pb-2 flex items-center justify-between pointer-events-none">
        <div className="flex items-center gap-2 px-3 py-1 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full text-[10px] font-black tracking-widest uppercase">
          <Sparkles size={12} /> Live Tools
        </div>
        <button onClick={() => setIsOpen(false)} className="p-2 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 pointer-events-auto">
          <ChevronRight size={18} />
        </button>
      </div>

      <div className="p-6 space-y-8">
        {/* Profile Selector */}
        <section>
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-4">Reading Profile</label>
          <div className="grid grid-cols-5 gap-2">
            {modes.map((m) => (
              <button
                key={m.id}
                onClick={() => updateSettings({ mode: m.id })}
                className={`flex flex-col items-center gap-2 p-2 rounded-2xl transition-all ${
                  settings.mode === m.id
                    ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-500/30'
                    : 'bg-slate-50 dark:bg-slate-800 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700'
                }`}
              >
                <div className="p-1">{m.icon}</div>
                <span className="text-[9px] font-bold">{m.label}</span>
              </button>
            ))}
          </div>
        </section>

        {/* Sliders */}
        <section className="space-y-6">
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-xs font-black text-slate-700 dark:text-slate-300">Text Density</span>
              <span className="text-[10px] font-mono text-indigo-500 font-bold">{settings.fontSize}px</span>
            </div>
            <input 
              type="range" min="14" max="36" value={settings.fontSize}
              onChange={(e) => updateSettings({ fontSize: Number(e.target.value) })}
              className="w-full accent-indigo-600 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-lg appearance-none cursor-pointer"
            />
          </div>
        </section>

        {/* AI Action Buttons */}
        <section className="space-y-3">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-2">AI Enhancement</label>
          <button 
            disabled={isHome || isSimplifying}
            onClick={onSimplify}
            className={`w-full p-4 rounded-2xl flex items-center justify-between group transition-all ${
              isHome ? 'bg-slate-50 text-slate-300 opacity-50 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg active:scale-95'
            }`}
          >
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg group-hover:rotate-12 transition-transform">
                <Zap size={18} className={isSimplifying ? 'animate-pulse' : ''} />
