                          <a key={i} href={s.uri} target="_blank" className="flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 text-slate-600 dark:text-slate-400 hover:text-indigo-600 transition-all rounded-xl text-sm font-bold border border-transparent hover:border-indigo-200">
                            <BookOpen size={14} /> {s.title}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </article>

                {/* Knowledge Quiz */}
                {quiz && quiz.length > 0 && (
                  <div className="p-12 bg-slate-50 dark:bg-slate-800/30 rounded-[3rem] border border-slate-200/60 dark:border-slate-700/60 shadow-inner">
                    <div className="flex items-center gap-4 mb-12">
                      <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-xl shadow-indigo-500/20"><Brain size={24} /></div>
                      <div>
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">Knowledge Check</h3>
                        <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1">Boost retention with a quick quiz</p>
                      </div>
                    </div>

                    <div className="space-y-16">
                      {quiz.map((q, idx) => (
                        <div key={idx} className="space-y-8">
                          <p className="text-2xl font-black text-slate-800 dark:text-white leading-tight">{idx + 1}. {q.question}</p>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => {
                              const isSelected = quizAnswers[idx] === oIdx;
                              const isCorrect = oIdx === q.correctAnswerIndex;
                              const hasAnswered = quizAnswers[idx] !== undefined;

                              return (
                                <button 
                                  key={oIdx} 
                                  disabled={hasAnswered}
                                  onClick={() => setQuizAnswers(prev => ({...prev, [idx]: oIdx}))}
                                  className={`p-6 text-left rounded-3xl border-2 transition-all font-bold text-lg flex items-center justify-between ${
                                    hasAnswered 
                                      ? isCorrect ? 'bg-emerald-50 border-emerald-500 text-emerald-800' : isSelected ? 'bg-rose-50 border-rose-500 text-rose-800' : 'bg-slate-100 dark:bg-slate-900 border-transparent opacity-40'
                                      : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-indigo-500 hover:shadow-xl'
                                  }`}
                                >
                                  <span>{opt}</span>
                                  {hasAnswered && isCorrect && <CheckCircle2 className="text-emerald-500" size={24} />}
                                  {hasAnswered && isSelected && !isCorrect && <XCircle className="text-rose-500" size={24} />}
                                </button>
                              );
                            })}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default SimulatedPage;

import React, { useState, useEffect } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion } from './types';
import { simplifyContent, generatePageContent, generateQuiz } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
  });

  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        next.hideSidebar = false;
        next.stopAnimations = false;

        switch (newSettings.mode) {
          case 'dyslexia':
            next.lineSpacing = 1.8;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'default':
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.highlightLinks = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      return;
    }

    window.speechSynthesis.cancel();
    const summaryEl = document.getElementById('ai-summary-content');
    const articleEl = document.getElementById('article-content-body');

    let textToRead = "";
    if (summaryEl) textToRead += `Summary: ${summaryEl.innerText}. `;
    if (articleEl) textToRead += `Article content: ${articleEl.innerText}`;

    if (textToRead.trim()) {
      const utterance = new SpeechSynthesisUtterance(textToRead);
      utterance.onstart = () => setIsSpeaking(true);
      utterance.onend = () => setIsSpeaking(false);
      utterance.onerror = () => setIsSpeaking(false);
      window.speechSynthesis.speak(utterance);
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { setSimplifiedContent(null); return; }
    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) return;

    setIsSimplifying(true);
    try {
      const result = await simplifyContent(text.substring(0, 4000));
      setSimplifiedContent(result);
    } finally {
      setIsSimplifying(false);
    }
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { setQuiz(null); return; }
    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) return;

    setIsGeneratingQuiz(true);
    try {
      const questions = await generateQuiz(text);
      setQuiz(questions);
    } finally {
      setIsGeneratingQuiz(false);
    }
  };

  const handleNavigate = async (query: string) => {
    const normalizedQuery = query.trim();
    if (!normalizedQuery || normalizedQuery === "Home" || normalizedQuery.toLowerCase() === "accessimod" || normalizedQuery.includes("accessimod.io/welcome")) {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      setSimplifiedContent(null);
      setQuiz(null);
      setHistory([]); // Reset history when going home
      return;
    }

    // Save current content to history before navigating if it's not the home page
    if (pageContent.title !== 'AccessiMod') {
      setHistory(prev => [...prev, pageContent]);
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);
    setQuiz(null);

    try {
      const content = await generatePageContent(normalizedQuery);
      setPageContent(content);
    } catch (err) {
      setPageContent({ title: "Error", contentHtml: "<p class='p-10 font-bold'>The AI architect couldn't build this content. Please try a different topic.</p>" });
    } finally {
      setIsLoadingPage(false);
    }
  };

  const handleBack = () => {
    if (history.length === 0) {
      // If no history, go back to Home
      if (pageContent.title !== "AccessiMod") {
        handleNavigate("Home");
      }
      return;
    }

    const newHistory = [...history];
    const previousPage = newHistory.pop();
    if (previousPage) {
      setHistory(newHistory);
      setPageContent(previousPage);
      setSimplifiedContent(null);
      setQuiz(null);
    }
  };

  const isHome = pageContent.title === 'AccessiMod';

  return (
    <div className="relative font-sans antialiased text-slate-900 dark:text-slate-100 transition-colors">
      <ControlPanel 
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={handleBack} canGoBack={!isHome} // Can always "go back" from a reader view
        isLoading={isLoadingPage} quiz={quiz}
      />
    </div>
  );
};

export default App;

