import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent, QuizQuestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Cleanly extracts and parses JSON from a string, handling markdown blocks or leading/trailing text.
 */
const extractAndParseJson = <T>(text: string): T => {
  try {
    // Find the first '{' or '[' and the last '}' or ']'
    const startIdx = Math.min(
      text.indexOf('{') === -1 ? Infinity : text.indexOf('{'),
      text.indexOf('[') === -1 ? Infinity : text.indexOf('[')
    );
    const endIdx = Math.max(
      text.lastIndexOf('}'),
      text.lastIndexOf(']')
    );

    if (startIdx === Infinity || endIdx === -1 || endIdx <= startIdx) {
      throw new Error("No JSON structure found in response");
    }

    const jsonStr = text.substring(startIdx, endIdx + 1);
    return JSON.parse(jsonStr) as T;
  } catch (error) {
    console.error("JSON Extraction failed. Raw text:", text);
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify the following text for a user with neurodivergent needs (ADHD/Dyslexia). 
      Provide a very short bullet-point summary first, then a simplified version of the main text.

      Return ONLY a JSON object:
      {
        "summary": "bullet points...",
        "simplifiedText": "simplified version..."
      }

      Text to process:
      ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            simplifiedText: { type: Type.STRING }
          },
          required: ["summary", "simplifiedText"]
        }
      }
    });

    return extractAndParseJson<SimplifiedContentResponse>(response.text);
  } catch (error) {
    console.error("Simplification Error:", error);
    return { 
      summary: "• Key point extraction unavailable.", 
      simplifiedText: "We couldn't simplify this specific page content right now." 
    };
  }
};

export const generateQuiz = async (text: string): Promise<QuizQuestion[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Based on the following content, generate a 3-question multiple-choice quiz. 
      Return ONLY a JSON array of objects with 'question', 'options' (array of 4), and 'correctAnswerIndex'.

      Content: ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswerIndex: { type: Type.INTEGER }
            },
            required: ["question", "options", "correctAnswerIndex"]
          }
        }
      }
    });

    return extractAndParseJson<QuizQuestion[]>(response.text);
  } catch (error) {
    console.error("Quiz Gen Error:", error);
    return [];
  }
};

export const generatePageContent = async (query: string): Promise<WebPageContent> => {
  // When using googleSearch, the response.text might not be strictly JSON.
  // We must prompt clearly and handle the output without responseSchema to avoid conflicts.
  const prompt = `Search for: "${query}".
    EXTRACT the core informative text. Remove all UI, ads, and sidebars.
    Return a highly semantic HTML <article> with clear headings and paragraphs.

    YOUR ENTIRE RESPONSE MUST BE A VALID JSON OBJECT:
    {
      "title": "Clear Title",
      "contentHtml": "<article class='space-y-6'>...</article>"
    }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.1, // Lower temperature for more consistent JSON
      }
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => {
      if (chunk.web) {
        return { title: chunk.web.title || "Source", uri: chunk.web.uri };
      }
      return null;
    }).filter((s: any) => s !== null && s.uri) || [];

    const data = extractAndParseJson<WebPageContent>(response.text);
    return {
      title: data.title || query,
      contentHtml: data.contentHtml || "<div class='p-8'>Unable to reconstruct content.</div>",
      sources: sources.length > 0 ? sources : undefined
    };
  } catch (error: any) {
    console.warn("Search grounded content failed, using internal knowledge fallback:", error);
    const fallbackResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt + "\n\nNote: Google Search tool failed, generate educational content from your internal knowledge.",
    });
    return extractAndParseJson<WebPageContent>(fallbackResponse.text);
  }
};

import React, { useState, useEffect } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion } from './types';
import { simplifyContent, generatePageContent, generateQuiz } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
    focusMode: false,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });

  // Prime speech synthesis voices
  useEffect(() => {
    const synth = window.speechSynthesis;
    const voices = synth.getVoices();
    if (synth.onvoiceschanged !== undefined) {
      synth.onvoiceschanged = () => synth.getVoices();
    }
  }, []);

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        next.hideSidebar = false;
        next.stopAnimations = false;
        next.focusMode = false;

        switch (newSettings.mode) {
          case 'dyslexia':
            next.lineSpacing = 1.8;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            next.focusMode = true;
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'default':
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.highlightLinks = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      return;
    }

    // Try to get text from summary first, then article body
    const summaryEl = document.getElementById('ai-summary-content');
    const articleEl = document.getElementById('article-content-body');

    let textToRead = "";
    if (summaryEl) {
      textToRead += "Summary. ";
      textToRead += summaryEl.innerText;
    } else if (articleEl) {
      textToRead = articleEl.innerText;
    }

    if (!textToRead.trim() && pageContent.title !== "AccessiMod") {
      textToRead = "The page is currently empty or loading.";
    }

    if (textToRead.trim()) {
      window.speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(textToRead.substring(0, 10000));

      // Select a decent voice if available
      const voices = window.speechSynthesis.getVoices();
      const preferredVoice = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      utterance.onstart = () => setIsSpeaking(true);
      utterance.onend = () => setIsSpeaking(false);
      utterance.onerror = (event) => {
        console.error("Speech Synthesis Error:", event);
        setIsSpeaking(false);
      };

      window.speechSynthesis.speak(utterance);
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { 
      setSimplifiedContent(null); 
      return; 
    }

    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) {
      alert("Please wait for content to load or navigate to a topic first.");
      return;
    }

    setIsSimplifying(true);
    try {
      const result = await simplifyContent(text);
      setSimplifiedContent(result);
    } catch (err) {
      console.error("Simplification failed:", err);
    } finally {
      setIsSimplifying(false);
    }
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { 
      setQuiz(null); 
      return; 
    }

    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) {
      alert("Navigate to a topic first to generate a quiz.");
      return;
    }

    setIsGeneratingQuiz(true);
    try {
      const result = await generateQuiz(text);
      if (result && result.length > 0) {
        setQuiz(result);
      } else {
        alert("Failed to generate a quiz for this content. Please try a different topic.");
      }
    } catch (err) {
      console.error("Quiz generation failed:", err);
    } finally {
      setIsGeneratingQuiz(false);
    }
  };

  const handleNavigate = async (query: string) => {
    const normalizedQuery = query.trim();
    if (!normalizedQuery || normalizedQuery === "Home" || normalizedQuery.toLowerCase() === "accessimod" || normalizedQuery.includes("accessimod.io/welcome")) {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      setSimplifiedContent(null);
      setQuiz(null);
      setHistory([]);
      setSettings(prev => ({ ...prev, focusMode: false }));
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      return;
    }

    if (pageContent.title !== 'AccessiMod') {
      setHistory(prev => [...prev, pageContent]);
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);
    setQuiz(null);
    window.speechSynthesis.cancel();
    setIsSpeaking(false);

    try {
      const content = await generatePageContent(normalizedQuery);
      setPageContent(content);
    } catch (err) {
      setPageContent({ title: "Error", contentHtml: "<div class='p-20 text-center font-bold text-xl'>We encountered an error loading this page. Please try another topic.</div>" });
    } finally {
      setIsLoadingPage(false);
    }
  };

  const handleBack = () => {
    if (history.length === 0) {
      if (pageContent.title !== "AccessiMod") {
        handleNavigate("Home");
      }
      return;
    }

    const newHistory = [...history];
    const previousPage = newHistory.pop();
    if (previousPage) {
      setHistory(newHistory);
      setPageContent(previousPage);
      setSimplifiedContent(null);
      setQuiz(null);
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    }
  };

  const isHome = pageContent.title === 'AccessiMod';

  return (
    <div className="relative font-sans antialiased text-slate-900 dark:text-slate-100 transition-colors">
      <ControlPanel 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={handleBack} canGoBack={!isHome}
        isLoading={isLoadingPage} quiz={quiz}
        onToggleSettings={() => setIsSettingsOpen(!isSettingsOpen)}
      />
    </div>
  );
};

export default App;

