export type AccessibilityMode = 'default' | 'dyslexia' | 'adhd' | 'high-contrast' | 'reading';

export interface AccessibilitySettings {
  mode: AccessibilityMode;
  fontSize: number; // Base pixel size (default 16)
  fontWeight: number; // 100-900 (default 400)
  lineSpacing: number; // Multiplier (default 1.5)
  letterSpacing: number; // px (default 0)
  fontFamily: string;
  showImages: boolean;
  highlightLinks: boolean;
  readingRuler: boolean; // For ADHD/Dyslexia tracking
  stopAnimations: boolean; // ADHD reduced motion
  hideSidebar: boolean; // ADHD distraction removal
  focusMode: boolean; // ADHD concentration tool
  readerMode: boolean; // Reader view toggle
}

export interface SimplifiedContentResponse {
  summary: string;
  simplifiedText: string;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswerIndex: number;
}

export interface WebPageContent {
  title: string;
  contentHtml: string; // The full page layout in HTML format
  sources?: { title: string; uri: string }[]; // Grounding sources from Google Search
}

import React, { useState, useEffect } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion } from './types';
import { simplifyContent, generatePageContent, generateQuiz } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
    focusMode: false,
    readerMode: false,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });

  const isHome = pageContent.title === 'AccessiMod';

  // Prime speech synthesis voices
  useEffect(() => {
    const synth = window.speechSynthesis;
    const voices = synth.getVoices();
    if (synth.onvoiceschanged !== undefined) {
      synth.onvoiceschanged = () => synth.getVoices();
    }
  }, []);

  const updateSettings = (newSettings: Partial<AccessibilitySettings>) => {
    setSettings(prev => {
      const next = { ...prev, ...newSettings };

      // Handle Reader Mode specific logic
      if ('readerMode' in newSettings) {
        if (newSettings.readerMode) {
          if (isHome) {
            // Trigger automatic simulation for "Home"
            setTimeout(() => handleNavigate("Latest Accessibility News"), 100);
          }
          next.mode = 'reading';
        } else {
          next.mode = 'default';
        }
      }

      if (newSettings.mode) {
        next.hideSidebar = false;
        next.stopAnimations = false;
        next.focusMode = false;
        next.readerMode = newSettings.mode === 'reading';

        switch (newSettings.mode) {
          case 'dyslexia':
            next.lineSpacing = 1.8;
            next.fontWeight = 500;
            break;
          case 'adhd':
            next.lineSpacing = 1.8;
            next.fontSize = 20;
            next.hideSidebar = true;
            next.stopAnimations = true;
            next.focusMode = true;
            break;
          case 'high-contrast':
            next.fontSize = 22;
            next.fontWeight = 700;
            next.highlightLinks = true;
            break;
          case 'reading':
            next.readerMode = true;
            break;
          case 'default':
            next.fontSize = 18;
            next.fontWeight = 400;
            next.lineSpacing = 1.6;
            next.highlightLinks = false;
            next.readerMode = false;
            break;
        }
      }
      return next;
    });
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      return;
    }

    const summaryEl = document.getElementById('ai-summary-content');
    const articleEl = document.getElementById('article-content-body');

    let textToRead = "";
    if (summaryEl) {
      textToRead += "Summary. ";
      textToRead += summaryEl.innerText;
    } else if (articleEl) {
      textToRead = articleEl.innerText;
    }

    if (!textToRead.trim() && !isHome) {
      textToRead = "The page is currently empty or loading.";
    }

    if (textToRead.trim()) {
      window.speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(textToRead.substring(0, 10000));
      const voices = window.speechSynthesis.getVoices();
      const preferredVoice = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) || voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;

      utterance.onstart = () => setIsSpeaking(true);
      utterance.onend = () => setIsSpeaking(false);
      utterance.onerror = (event) => {
        console.error("Speech Synthesis Error:", event);
        setIsSpeaking(false);
      };

      window.speechSynthesis.speak(utterance);
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { 
      setSimplifiedContent(null); 
      return; 
    }

    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) {
      alert("Please search for a topic first to use AI Smart Focus.");
      return;
    }

    setIsSimplifying(true);
    try {
      const result = await simplifyContent(text);
      setSimplifiedContent(result);
    } catch (err) {
      console.error("Simplification failed:", err);
    } finally {
      setIsSimplifying(false);
    }
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { 
      setQuiz(null); 
      return; 
    }

    const articleEl = document.getElementById('article-content-body');
    const text = articleEl?.innerText || "";
    if (!text.trim()) {
      alert("Please search for a topic first to generate a quiz.");
      return;
    }

    setIsGeneratingQuiz(true);
    try {
      const result = await generateQuiz(text);
      if (result && result.length > 0) {
        setQuiz(result);
      } else {
        alert("Failed to generate a quiz for this content. Please try a different topic.");
      }
    } catch (err) {
      console.error("Quiz generation failed:", err);
    } finally {
      setIsGeneratingQuiz(false);
    }
  };

  const handleNavigate = async (query: string) => {
    const normalizedQuery = query.trim();
    if (!normalizedQuery || normalizedQuery === "Home" || normalizedQuery.toLowerCase() === "accessimod" || normalizedQuery.includes("accessimod.io/welcome")) {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      setSimplifiedContent(null);
      setQuiz(null);
      setHistory([]);
      setSettings(prev => ({ ...prev, focusMode: false, readerMode: false, mode: 'default' }));
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      return;
    }

    if (pageContent.title !== 'AccessiMod') {
      setHistory(prev => [...prev, pageContent]);
    }

    setIsLoadingPage(true);
    setSimplifiedContent(null);
    setQuiz(null);
    window.speechSynthesis.cancel();
    setIsSpeaking(false);

    try {
      const content = await generatePageContent(normalizedQuery);
      setPageContent(content);
    } catch (err) {
      setPageContent({ title: "Error", contentHtml: "<div class='p-20 text-center font-bold text-xl'>We encountered an error loading this page. Please try another topic.</div>" });
    } finally {
      setIsLoadingPage(false);
    }
  };

  const handleBack = () => {
    if (history.length === 0) {
      if (!isHome) {
        handleNavigate("Home");
      }
      return;
    }

    const newHistory = [...history];
    const previousPage = newHistory.pop();
    if (previousPage) {
      setHistory(newHistory);
      setPageContent(previousPage);
      setSimplifiedContent(null);
      setQuiz(null);
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    }
  };

  return (
    <div className="relative font-sans antialiased text-slate-900 dark:text-slate-100 transition-colors">
      <ControlPanel 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={handleBack} canGoBack={!isHome}
        isLoading={isLoadingPage} quiz={quiz}
        onToggleSettings={() => setIsSettingsOpen(!isSettingsOpen)}
      />
    </div>
  );
};

export default App;

