    '--text-color': isHighContrast ? '#ffff00' : isReading ? (isDarkMode ? '#e0e0e0' : '#2e2e2e') : 'var(--theme-text)',
    '--font-size': `${settings.fontSize}px`,
    '--font-weight': settings.fontWeight,
    '--line-height': `${settings.lineSpacing}`,
  } as React.CSSProperties;

  const isHome = content.title === 'AccessiMod';
  const exampleTopics = ["Black Holes", "Modern Architecture", "Cognitive Behavioral Therapy", "Sustainable Energy", "The History of Tea"];

  return (
    <div className="flex flex-col items-center justify-start p-0 sm:p-4 transition-colors duration-700 overflow-x-hidden">
      <style>
        {`
        /* Global Dyslexia Mode */
        .dyslexia-mode * { 
          font-family: "Comic Sans MS", "Chalkboard SE", "cursive", sans-serif !important; 
          letter-spacing: 0.12em !important; 
          word-spacing: 0.25em !important;
        }

        /* Global High Contrast Mode (Overrides everything) */
        .high-contrast-mode #simulated-viewport { 
          background-color: #000000 !important; 
          color: #ffff00 !important; 
        }
        .high-contrast-mode #simulated-viewport * { 
          background-color: #000000 !important; 
          color: #ffff00 !important; 
          border-color: #ffff00 !important; 
        }
        .high-contrast-mode #simulated-viewport a, 
        .high-contrast-mode #simulated-viewport button { 
          text-decoration: underline !important; 
          color: #00ffff !important; 
          font-weight: bold !important; 
        }

        /* Link Highlighting */
        ${settings.highlightLinks ? `
          #simulated-viewport a { background-color: #ffeb3b !important; color: #000 !important; border: 2px solid #000 !important; padding: 2px 4px !important; font-weight: bold !important; border-radius: 4px !important; }
        ` : ''}

        /* Global Focus Mode Styles */
        .focus-mode-active #simulated-viewport p, 
        .focus-mode-active #simulated-viewport h1, 
        .focus-mode-active #simulated-viewport h2, 
