  const handleBionicText = (html: string) => {
    if (!settings.bionicReading) return html;
    const temp = document.createElement('div');
    temp.innerHTML = html;
    const processNodes = (node: Node) => {
      if (node.nodeType === 3 && node.nodeValue?.trim()) {
        const words = node.nodeValue.split(/(\s+)/);
        const fragment = document.createDocumentFragment();
        words.forEach(word => {
          if (/\s+/.test(word)) {
            fragment.appendChild(document.createTextNode(word));
          } else {
            const span = document.createElement('span');
            const mid = Math.ceil(word.length * 0.4);
            span.innerHTML = `<b style="opacity: 1; font-weight: 800;">${word.substring(0, mid)}</b><span style="opacity: 0.8;">${word.substring(mid)}</span>`;
            fragment.appendChild(span);
          }
        });
        node.parentNode?.replaceChild(fragment, node);
      } else {
        node.childNodes.forEach(processNodes);
      }
    };
    processNodes(temp);
    return temp.innerHTML;
  };

