            <button 
              onClick={() => setIsChatOpen(!isChatOpen)} 
              className={`p-5 rounded-full shadow-2xl transition-all active:scale-90 flex items-center justify-center ${isChatOpen ? 'bg-rose-500 text-white rotate-90' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-500/30'}`}
            >
              {isChatOpen ? <X size={28} /> : <MessageCircle size={28} />}
            </button>
          </div>
        )}
      </div>
    </div>
  );
