                <form onSubmit={handleChatSubmit} className="p-4 bg-white dark:bg-slate-800 border-t border-theme-border flex gap-2">
                  <input 
                    type="text" 
                    value={chatInput} 
                    onChange={(e) => setChatInput(e.target.value)} 
