                    className="flex-1 px-5 py-3 rounded-2xl bg-slate-100 dark:bg-slate-900 outline-none text-sm font-bold focus:ring-2 ring-indigo-500/20"
                  />
                  <button type="submit" disabled={isChatLoading || !chatInput.trim()} className="p-3 bg-indigo-600 text-white rounded-2xl hover:bg-indigo-700 transition-all disabled:opacity-50 active:scale-95 shadow-lg shadow-indigo-500/20">
                    <Send size={18} />
                  </button>
                </form>
              </div>
            )}
            <button 
              onClick={() => setIsChatOpen(!isChatOpen)} 
              className={`p-5 rounded-full shadow-2xl transition-all active:scale-90 flex items-center justify-center ${isChatOpen ? 'bg-rose-500 text-white rotate-90' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-500/30'}`}
            >
              {isChatOpen ? <X size={28} /> : <MessageCircle size={28} />}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

