import { GoogleGenAI, Type } from "@google/genai";
import { SimplifiedContentResponse, WebPageContent, QuizQuestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Custom error handler to detect quota exhaustion
 */
const handleApiError = (error: any): string => {
  const errorStr = String(error);
  if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.includes("quota")) {
    return "QUOTA_EXCEEDED";
  }
  return "GENERAL_ERROR";
};

const extractAndParseJson = <T>(text: string): T => {
  try {
    const startIdx = Math.min(
      text.indexOf('{') === -1 ? Infinity : text.indexOf('{'),
      text.indexOf('[') === -1 ? Infinity : text.indexOf('[')
    );
    const endIdx = Math.max(text.lastIndexOf('}'), text.lastIndexOf(']'));
    if (startIdx === Infinity || endIdx === -1 || endIdx <= startIdx) {
      throw new Error("No JSON found");
    }
    const jsonStr = text.substring(startIdx, endIdx + 1);
    return JSON.parse(jsonStr) as T;
  } catch (error) {
    console.error("Extraction failed:", text);
    throw error;
  }
};

export const simplifyContent = async (text: string): Promise<SimplifiedContentResponse | string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simplify this for neurodivergent needs. Return JSON: {summary, simplifiedText}. Text: ${text.substring(0, 25000)}`,
      config: { responseMimeType: "application/json" }
    });
    return extractAndParseJson<SimplifiedContentResponse>(response.text);
  } catch (error) {
    return handleApiError(error);
  }
};

export const rewriteContent = async (text: string, level: number): Promise<string> => {
  const prompt = level === 1
    ? `Rewrite this entire text for a 5-year-old using simple words and emojis. Maintain all core information but simplify vocabulary. Preserve HTML structure (p, h1, h2). Text: ${text.substring(0, 25000)}`
    : `Rewrite this entire text for a PhD student using expert academic terminology and complex logic. Preserve HTML structure (p, h1, h2). Text: ${text.substring(0, 25000)}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { 
        systemInstruction: "You are an expert editor. You output content as pure HTML fragments. Do not truncate the text, rewrite the entire content provided." 
      }
    });
    return response.text.replace(/```html|```/g, '').trim();
  } catch (error) {
    return handleApiError(error);
  }
};

export const askPageQuestion = async (context: string, question: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are an accessibility assistant. Answer the user's question about the following text.

      CONTEXT:
      ${context.substring(0, 25000)}

      QUESTION:
      ${question}`,
    });
    return response.text;
  } catch (error) {
    const errType = handleApiError(error);
    return errType === "QUOTA_EXCEEDED" 
      ? "I've hit my usage limit for the moment. Please wait a minute before asking another question!" 
      : "I'm sorry, I couldn't process that question right now.";
  }
};

export const generateQuiz = async (text: string): Promise<QuizQuestion[] | string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a 3-question MCQ quiz based on: ${text.substring(0, 20000)}. Return JSON array.`,
      config: { responseMimeType: "application/json" }
    });
    return extractAndParseJson<QuizQuestion[]>(response.text);
  } catch (error) {
    return handleApiError(error);
  }
};

export const generatePageContent = async (query: string): Promise<WebPageContent | string> => {
  const prompt = `Search for: "${query}". Extract full informative text (at least 2000 words if available). Return JSON: {title, contentHtml}.`;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], temperature: 0.1 }
    });
    const data = extractAndParseJson<WebPageContent>(response.text);
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null).filter((s: any) => s && s.uri) || [];
    return { ...data, sources: sources.length > 0 ? sources : undefined };
  } catch (error) {
    return handleApiError(error);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion, ChatMessage } from './types';
import { simplifyContent, generatePageContent, generateQuiz, askPageQuestion, rewriteContent } from './services/geminiService';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') return window.matchMedia('(prefers-color-scheme: dark)').matches;
    return false;
  });

  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
    focusMode: false,
    readerMode: false,
    complexityLevel: 2,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [isRewriting, setIsRewriting] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });
  const [apiError, setApiError] = useState<string | null>(null);

  const complexityCache = useRef<Record<number, string>>({});
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const isHome = pageContent.title === 'AccessiMod';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
  }, [isDarkMode]);

  // Clear API error after 10 seconds
  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 10000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const updateSettings = async (newSettings: Partial<AccessibilitySettings>) => {
    // Handle Complexity Change
    if ('complexityLevel' in newSettings && newSettings.complexityLevel !== settings.complexityLevel) {
      const level = newSettings.complexityLevel!;
      if (complexityCache.current[level]) {
        setPageContent(prev => ({ ...prev, contentHtml: complexityCache.current[level] }));
        setSettings(prev => ({ ...prev, complexityLevel: level }));
      } else if (!isHome) {
        setIsRewriting(true);
        setApiError(null);
        const originalText = complexityCache.current[2] || pageContent.contentHtml;
        const result = await rewriteContent(originalText, level);

        if (result === "QUOTA_EXCEEDED") {
          setApiError("AI Usage Limit Reached");
        } else {
          complexityCache.current[level] = result;
          setPageContent(prev => ({ ...prev, contentHtml: result }));
          setSettings(prev => ({ ...prev, complexityLevel: level }));
        }
        setIsRewriting(false);
      } else {
        setSettings(prev => ({ ...prev, complexityLevel: level }));
      }
      return;
    }

    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if ('readerMode' in newSettings) {
        if (newSettings.readerMode && isHome) setTimeout(() => handleNavigate("Latest Accessibility News"), 100);
        if (newSettings.readerMode) next.mode = 'reading';
        else if (prev.mode === 'reading') next.mode = 'default';
      }
      if (newSettings.mode) {
        if (newSettings.mode === 'reading') {
          next.readerMode = true;
          if (isHome) setTimeout(() => handleNavigate("Latest Accessibility News"), 100);
        } else {
          next.focusMode = newSettings.mode === 'adhd';
        }
        switch (newSettings.mode) {
          case 'dyslexia': next.lineSpacing = 1.8; next.fontWeight = 500; break;
          case 'adhd': next.lineSpacing = 1.8; next.fontSize = 20; next.stopAnimations = true; next.focusMode = true; break;
          case 'high-contrast': next.fontSize = 22; next.fontWeight = 700; next.highlightLinks = true; break;
          case 'default': next.fontSize = 18; next.fontWeight = 400; next.lineSpacing = 1.6; next.highlightLinks = false; next.focusMode = false; break;
        }
      }
      return next;
    });
  };

  const handleSendMessage = async (text: string) => {
    const userMsg: ChatMessage = { role: 'user', text };
    setChatMessages(prev => [...prev, userMsg]);
    setIsChatLoading(true);
    setApiError(null);

    const context = document.getElementById('article-content-body')?.innerText || "";
    const responseText = await askPageQuestion(context, text);

    const modelMsg: ChatMessage = { role: 'model', text: responseText };
    setChatMessages(prev => [...prev, modelMsg]);
    setIsChatLoading(false);
  };

  const handleSpeak = () => {
    if (isSpeaking) { window.speechSynthesis.cancel(); setIsSpeaking(false); return; }
    const articleEl = document.getElementById('article-content-body');
    const textToRead = articleEl?.innerText || (isHome ? "Welcome to AccessiMod" : "");
    if (textToRead.trim()) {
      window.speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(textToRead.substring(0, 5000));
      utterance.onstart = () => setIsSpeaking(true);
      utterance.onend = () => setIsSpeaking(false);
      window.speechSynthesis.speak(utterance);
    }
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { setSimplifiedContent(null); return; }
    const articleEl = document.getElementById('article-content-body');
    if (!articleEl?.innerText) return;
    setIsSimplifying(true);
    setApiError(null);
    try {
      const result = await simplifyContent(articleEl.innerText);
      if (result === "QUOTA_EXCEEDED") {
        setApiError("AI Usage Limit Reached");
      } else {
        setSimplifiedContent(result as SimplifiedContentResponse);
      }
    } finally { setIsSimplifying(false); }
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { setQuiz(null); return; }
    const articleEl = document.getElementById('article-content-body');
    if (!articleEl?.innerText) return;
    setIsGeneratingQuiz(true);
    setApiError(null);
    try {
      const result = await generateQuiz(articleEl.innerText);
      if (result === "QUOTA_EXCEEDED") {
        setApiError("AI Usage Limit Reached");
      } else {
        setQuiz(result as QuizQuestion[]);
      }
    } finally { setIsGeneratingQuiz(false); }
  };

  const handleNavigate = async (query: string) => {
    const q = query.trim();
    if (!q || q === "Home" || q.toLowerCase() === "accessimod") {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      complexityCache.current = {};
      setChatMessages([]);
      setSimplifiedContent(null);
      setQuiz(null);
      setSettings(prev => ({ ...prev, focusMode: false, readerMode: false, mode: 'default', complexityLevel: 2 }));
      return;
    }
    if (pageContent.title !== 'AccessiMod') setHistory(prev => [...prev, pageContent]);
    setIsLoadingPage(true);
    setChatMessages([]);
    setSimplifiedContent(null);
    setQuiz(null);
    setApiError(null);
    complexityCache.current = {}; 
    try {
      const content = await generatePageContent(q);
      if (content === "QUOTA_EXCEEDED") {
        setApiError("AI Usage Limit Reached");
      } else {
        const data = content as WebPageContent;
        setPageContent(data);
        complexityCache.current[2] = data.contentHtml;
        setSettings(prev => ({ ...prev, complexityLevel: 2 }));
      }
    } finally { setIsLoadingPage(false); }
  };

  const handleBack = () => {
    if (history.length === 0) { if (!isHome) handleNavigate("Home"); return; }
    const newHistory = [...history];
    const prev = newHistory.pop();
    if (prev) { 
      setHistory(newHistory); 
      setPageContent(prev); 
      setChatMessages([]); 
      setSimplifiedContent(null); 
      setQuiz(null);
      setApiError(null);
      complexityCache.current = { 2: prev.contentHtml };
      setSettings(prevSet => ({ ...prevSet, complexityLevel: 2 }));
    }
  };

  const wrapperClasses = [
    "relative font-sans antialiased text-slate-900 dark:text-slate-100 transition-colors min-h-screen",
    settings.mode === 'dyslexia' ? 'dyslexia-mode' : '',
    settings.focusMode ? 'focus-mode-active' : '',
    settings.mode === 'high-contrast' ? 'high-contrast-mode' : ''
  ].join(' ');

  return (
    <div className={wrapperClasses}>
      <ControlPanel 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)}
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={handleBack} canGoBack={!isHome}
        isLoading={isLoadingPage} quiz={quiz}
        onToggleSettings={() => setIsSettingsOpen(!isSettingsOpen)}
        isDarkMode={isDarkMode} toggleTheme={toggleTheme}
        chatMessages={chatMessages} onSendMessage={handleSendMessage}
        isChatLoading={isChatLoading}
        isRewriting={isRewriting}
        apiError={apiError}
      />
    </div>
  );
};

