                  />
                  <button type="submit" disabled={isChatLoading || !chatInput.trim()} className={`p-3 rounded-2xl transition-all disabled:opacity-50 active:scale-95 shadow-lg ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}>
                    <Send size={18} />
