            )}
            <button 
              onClick={() => setIsChatOpen(!isChatOpen)} 
              className={`p-5 rounded-full shadow-2xl transition-all active:scale-90 flex items-center justify-center ${isChatOpen ? 'bg-rose-500 text-white' : (isHighContrast ? 'bg-[#ffff00] text-black shadow-[#ffff00]/20' : 'bg-indigo-600 text-white hover:bg-indigo-700')}`}
            >
              {isChatOpen ? <X size={28} /> : <MessageCircle size={28} />}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

