    '--line-height': `${settings.lineSpacing}`,
  } as React.CSSProperties;

  const handleChatSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim()) return;
    onSendMessage(chatInput);
    setChatInput('');
  };

  return (
    <div className="flex flex-col items-center justify-start p-0 sm:p-4 min-h-screen transition-all duration-300">
      <style>{`
        .dyslexia-mode * { font-family: "Comic Sans MS", cursive !important; letter-spacing: 0.12em !important; word-spacing: 0.2em !important; }
        .focus-mode-active #simulated-viewport p, .focus-mode-active #simulated-viewport h1, .focus-mode-active #simulated-viewport h2 {
          opacity: 0.25; filter: blur(3px); transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
        }
        .focus-mode-active #simulated-viewport p:hover, .focus-mode-active #simulated-viewport h1:hover {
          opacity: 1 !important; filter: blur(0) !important; transform: scale(1.02); z-index: 10;
        }
        .high-contrast-mode button { border: 2px solid #ffff00 !important; }
      `}</style>

      <div className="w-full max-w-[1400px] flex flex-col rounded-none sm:rounded-[2.5rem] overflow-hidden shadow-[0_32px_64px_-16px_rgba(0,0,0,0.15)] bg-theme-surface border border-theme-border h-[100vh] sm:h-[94vh] relative transition-all duration-300">
        <BrowserHeader 
          currentTopic={content.title} 
          isLoading={isLoading} 
          canGoBack={canGoBack} 
          onBack={onBack} 
          onNavigate={onNavigate} 
          onHome={() => onNavigate("Home")} 
          onToggleSettings={onToggleSettings} 
          isDarkMode={isDarkMode} 
          toggleTheme={toggleTheme} 
        />

        <div 
          id="simulated-viewport" 
          className="flex-1 overflow-y-auto relative custom-scrollbar min-h-0" 
          style={{ backgroundColor: styleVars['--bg-color'] }}
        >
          {apiError && (
            <div className="sticky top-0 z-[100] w-full px-8 pt-4 pointer-events-none">
              <div className="pointer-events-auto bg-rose-50 dark:bg-rose-900/20 border border-rose-200 dark:border-rose-500/20 p-4 rounded-3xl flex items-center justify-between shadow-xl shadow-rose-500/5 animate-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
