            <div className="max-w-4xl mx-auto p-8 sm:p-24 space-y-16">
              {isRewriting && (
                <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                  <div className="bg-white dark:bg-slate-800 p-8 rounded-[3rem] shadow-2xl border border-indigo-500/20 flex flex-col items-center animate-in zoom-in-95 duration-300">
                    <div className="p-4 bg-indigo-600 rounded-full text-white animate-spin mb-4 shadow-xl shadow-indigo-500/30">
                      <Sparkles size={32} />
                    </div>
                    <h3 className="text-xl font-black text-indigo-600 dark:text-indigo-400">✨ Updating Context...</h3>
                  </div>
