              )}

              {simplifiedContent && (
                <div className={`p-10 rounded-[3rem] shadow-[0_32px_64px_-16px_rgba(99,102,241,0.3)] relative overflow-hidden group transition-colors ${isHighContrast ? 'bg-black border-4 border-[#ffff00] text-[#ffff00]' : 'bg-indigo-600 text-white'}`}>
                  <div className="absolute top-0 right-0 p-12 opacity-10 group-hover:rotate-12 transition-transform">
                    <Sparkles size={140} />
                  </div>
                  <div className="flex items-center gap-2 mb-6"><Zap size={20} /><h3 className="font-black uppercase tracking-widest text-[10px]">AI ADAPTIVE SUMMARY</h3></div>
                  <p className="text-3xl font-black leading-tight mb-8 tracking-tighter">{simplifiedContent.simplifiedText}</p>
                  <div className={`text-lg leading-relaxed font-medium space-y-2 ${isHighContrast ? 'opacity-100' : 'opacity-90'}`} dangerouslySetInnerHTML={{ __html: simplifiedContent.summary.replace(/\n/g, '<br/>') }} />
