                />
              </article>

              {quiz && quiz.length > 0 && (
                <div className={`p-12 rounded-[3rem] border shadow-inner space-y-12 transition-colors ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-slate-50 dark:bg-slate-800/50 border-theme-border'}`}>
                  <div className="flex items-center gap-4">
                    <div className={`p-4 rounded-3xl shadow-xl ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}><Brain size={28} /></div>
                    <div>
                      <h3 className={`text-2xl font-black ${isHighContrast ? 'text-[#ffff00]' : 'text-slate-800 dark:text-slate-100'}`}>Retention Quiz</h3>
                    </div>
                  </div>
                  <div className="space-y-12">
                    {quiz.map((q, idx) => (
                      <div key={idx} className="space-y-6">
                        <p className={`font-black text-xl leading-tight ${isHighContrast ? 'text-[#ffff00]' : 'text-slate-800 dark:text-slate-100'}`}>{idx + 1}. {q.question}</p>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                          {q.options.map((opt, oIdx) => (
                            <button 
                              key={oIdx} 
                              onClick={() => setQuizAnswers(prev => ({...prev, [idx]: oIdx}))} 
                              className={`p-6 text-left rounded-[1.5rem] border-2 transition-all font-bold text-lg flex items-center justify-between group ${
                                quizAnswers[idx] === oIdx 
                                  ? (oIdx === q.correctAnswerIndex ? 'bg-emerald-500 border-emerald-400 text-white' : 'bg-rose-500 border-rose-400 text-white') 
                                  : (isHighContrast ? 'bg-black border-[#ffff00] text-[#ffff00]' : 'bg-white dark:bg-slate-900 border-transparent hover:border-indigo-500/50 shadow-sm')
                              }`}
                            >
                              <span>{opt}</span>
                              <ArrowRight size={18} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                            </button>
                          ))}
