              )}
            </div>
          )}

          {settings.readingRuler && (
            <div className="fixed left-0 w-full pointer-events-none z-50 bg-indigo-500/10 backdrop-blur-[2px] border-y-2 border-indigo-500/20 h-20 shadow-[0_0_80px_rgba(99,102,241,0.1)]" style={{ top: mouseY - 40 }} />
          )}
        </div>

        {/* Floating Chat */}
        {!isHome && (
          <div className="absolute bottom-8 right-8 z-[100] flex flex-col items-end gap-4">
            {isChatOpen && (
              <div className={`w-[380px] h-[520px] rounded-[2.5rem] shadow-[0_32px_128px_-16px_rgba(0,0,0,0.4)] border flex flex-col overflow-hidden animate-in slide-in-from-bottom-8 transition-colors ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-theme-surface border-theme-border'}`}>
                <div className={`p-6 flex items-center justify-between shadow-lg ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}>
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-xl ${isHighContrast ? 'bg-black/10' : 'bg-white/20'}`}><MessageCircle size={18} /></div>
                    <h4 className="font-black text-sm uppercase">Assistant</h4>
                  </div>
                  <button onClick={() => setIsChatOpen(false)} className="p-2 rounded-xl"><X size={20}/></button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50 dark:bg-slate-900/50 custom-scrollbar">
                  {chatMessages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] p-4 rounded-3xl text-sm font-medium shadow-sm ${msg.role === 'user' ? (isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white') : (isHighContrast ? 'bg-black border-2 border-[#ffff00] text-[#ffff00]' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-theme-border')}`}>
                        {msg.text}
