                  ))}
                  {isChatLoading && (
                    <div className="flex justify-start">
                      <div className={`p-4 rounded-3xl border flex gap-1 ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-white dark:bg-slate-800 border-theme-border'}`}>
