              {quiz && quiz.length > 0 && (
                <div className={`p-6 sm:p-12 rounded-3xl sm:rounded-[3rem] border shadow-inner space-y-8 sm:space-y-12 transition-colors ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-slate-50 dark:bg-slate-800/50 border-theme-border'}`}>
                  <div className="flex items-center gap-4">
                    <div className={`p-3 sm:p-4 rounded-2xl sm:rounded-3xl shadow-xl shrink-0 ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}><Brain size={24} className="sm:w-7 sm:h-7" /></div>
                    <div>
                      <h3 className={`text-xl sm:text-2xl font-black ${isHighContrast ? 'text-[#ffff00]' : 'text-slate-800 dark:text-slate-100'}`}>Retention Quiz</h3>
                    </div>
                  </div>
                  <div className="space-y-10 sm:space-y-12">
                    {quiz.map((q, idx) => (
                      <div key={idx} className="space-y-4 sm:space-y-6">
                        <p className={`font-black text-lg sm:text-xl leading-tight ${isHighContrast ? 'text-[#ffff00]' : 'text-slate-800 dark:text-slate-100'}`}>{idx + 1}. {q.question}</p>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3 sm:gap-4">
                          {q.options.map((opt, oIdx) => (
                            <button 
                              key={oIdx} 
                              onClick={() => setQuizAnswers(prev => ({...prev, [idx]: oIdx}))} 
                              className={`p-4 sm:p-6 text-left rounded-2xl sm:rounded-[1.5rem] border-2 transition-all font-bold text-base sm:text-lg flex items-center justify-between group ${
                                quizAnswers[idx] === oIdx 
                                  ? (oIdx === q.correctAnswerIndex ? 'bg-emerald-500 border-emerald-400 text-white' : 'bg-rose-500 border-rose-400 text-white') 
                                  : (isHighContrast ? 'bg-black border-[#ffff00] text-[#ffff00]' : 'bg-white dark:bg-slate-900 border-transparent hover:border-indigo-500/50 shadow-sm')
                              }`}
                            >
                              <span>{opt}</span>
                              <ArrowRight size={18} className="opacity-0 group-hover:opacity-100 transition-opacity shrink-0 ml-2" />
                            </button>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {settings.readingRuler && (
            <div className="fixed left-0 w-full pointer-events-none z-[9999] bg-indigo-500/10 backdrop-blur-[2px] border-y-2 border-indigo-500/20 h-20 shadow-[0_0_80px_rgba(99,102,241,0.1)]" style={{ top: mouseY - 40 }} />
          )}
        </div>

        {/* Floating Chat */}
        {!isHome && (
          <div className="absolute bottom-4 right-4 sm:bottom-8 sm:right-8 z-[100] flex flex-col items-end gap-4">
            {isChatOpen && (
              <div className={`w-[calc(100vw-2rem)] sm:w-[380px] h-[450px] sm:h-[520px] rounded-3xl sm:rounded-[2.5rem] shadow-[0_32px_128px_-16px_rgba(0,0,0,0.4)] border flex flex-col overflow-hidden animate-in slide-in-from-bottom-8 transition-colors ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-theme-surface border-theme-border'}`}>
                <div className={`p-4 sm:p-6 flex items-center justify-between shadow-lg ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}>
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-xl ${isHighContrast ? 'bg-black/10' : 'bg-white/20'}`}><MessageCircle size={18} /></div>
                    <h4 className="font-black text-sm uppercase">Assistant</h4>
                  </div>
                  <button onClick={() => setIsChatOpen(false)} className="p-2 rounded-xl"><X size={20}/></button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-4 sm:space-y-6 bg-slate-50/50 dark:bg-slate-900/50 custom-scrollbar">
                  {chatMessages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[90%] sm:max-w-[85%] p-3 sm:p-4 rounded-2xl sm:rounded-3xl text-sm font-medium shadow-sm ${msg.role === 'user' ? (isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white') : (isHighContrast ? 'bg-black border-2 border-[#ffff00] text-[#ffff00]' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-theme-border')}`}>
                        {msg.text}
                      </div>
                    </div>
                  ))}
                  {isChatLoading && (
                    <div className="flex justify-start">
                      <div className={`p-3 sm:p-4 rounded-2xl sm:rounded-3xl border flex gap-1 ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-white dark:bg-slate-800 border-theme-border'}`}>
                        <div className={`w-1.5 h-1.5 rounded-full animate-bounce ${isHighContrast ? 'bg-[#ffff00]' : 'bg-indigo-500'}`} />
                        <div className={`w-1.5 h-1.5 rounded-full animate-bounce [animation-delay:0.2s] ${isHighContrast ? 'bg-[#ffff00]' : 'bg-indigo-500'}`} />
                      </div>
                    </div>
                  )}
                  <div ref={chatEndRef} />
                </div>

                <form onSubmit={handleChatSubmit} className={`p-3 sm:p-4 border-t flex gap-2 ${isHighContrast ? 'bg-black border-[#ffff00]' : 'bg-white dark:bg-slate-800 border-theme-border'}`}>
                  <input 
                    type="text" 
                    value={chatInput} 
                    onChange={(e) => setChatInput(e.target.value)} 
                    placeholder="Ask..." 
                    className={`flex-1 px-4 sm:px-5 py-2 sm:py-3 rounded-xl sm:rounded-2xl outline-none text-sm font-bold ${isHighContrast ? 'bg-black border border-[#ffff00] text-[#ffff00]' : 'bg-slate-100 dark:bg-slate-900'}`}
                  />
                  <button type="submit" className={`p-2 sm:p-3 rounded-xl sm:rounded-2xl transition-all ${isHighContrast ? 'bg-[#ffff00] text-black' : 'bg-indigo-600 text-white'}`}>
                    <Send size={18} className="w-5 h-5 sm:w-6 sm:h-6" />
                  </button>
                </form>
              </div>
            )}
            <button 
              onClick={() => setIsChatOpen(!isChatOpen)} 
              className={`p-4 sm:p-5 rounded-full shadow-2xl transition-all active:scale-90 flex items-center justify-center ${isChatOpen ? 'bg-rose-500 text-white' : (isHighContrast ? 'bg-[#ffff00] text-black shadow-[#ffff00]/20' : 'bg-indigo-600 text-white hover:bg-indigo-700')}`}
            >
              {isChatOpen ? <X size={24} className="sm:w-7 sm:h-7" /> : <MessageCircle size={24} className="sm:w-7 sm:h-7" />}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default SimulatedPage;

import React, { useState, useEffect, useRef } from 'react';
import ControlPanel from './components/ControlPanel';
import SimulatedPage from './components/SimulatedPage';
import { AccessibilitySettings, SimplifiedContentResponse, WebPageContent, QuizQuestion, ChatMessage } from './types';
import { simplifyContent, generatePageContent, generateQuiz, askPageQuestion, rewriteContent } from './services/geminiService';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') return window.matchMedia('(prefers-color-scheme: dark)').matches;
    return false;
  });

  const [settings, setSettings] = useState<AccessibilitySettings>({
    mode: 'default',
    fontSize: 18,
    fontWeight: 400,
    lineSpacing: 1.6,
    letterSpacing: 0,
    fontFamily: 'Inter, system-ui, sans-serif',
    showImages: true,
    highlightLinks: false,
    readingRuler: false,
    stopAnimations: false,
    hideSidebar: false,
    focusMode: false,
    readerMode: false,
    complexityLevel: 2,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [simplifiedContent, setSimplifiedContent] = useState<SimplifiedContentResponse | null>(null);
  const [isSimplifying, setIsSimplifying] = useState(false);
  const [isLoadingPage, setIsLoadingPage] = useState(false);
  const [isGeneratingQuiz, setIsGeneratingQuiz] = useState(false);
  const [isRewriting, setIsRewriting] = useState(false);
  const [quiz, setQuiz] = useState<QuizQuestion[] | null>(null);
  const [history, setHistory] = useState<WebPageContent[]>([]);
  const [pageContent, setPageContent] = useState<WebPageContent>({ title: "AccessiMod", contentHtml: "" });
  const [apiError, setApiError] = useState<string | null>(null);

  // TTS State and Refs
  const [speechQueue, setSpeechQueue] = useState<string[]>([]);
  const [currentSentenceIndex, setCurrentSentenceIndex] = useState(-1);
  const complexityCache = useRef<Record<number, string>>({});
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const isHome = pageContent.title === 'AccessiMod';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkMode);
  }, [isDarkMode]);

  useEffect(() => {
    if (apiError) {
      const timer = setTimeout(() => setApiError(null), 10000);
      return () => clearTimeout(timer);
    }
  }, [apiError]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  /**
   * Sequential Playback Logic
   * Reads one sentence, and on end, moves to the next.
   */
  const speakSentence = (index: number, queue: string[]) => {
    if (index >= queue.length) {
      setIsSpeaking(false);
      setCurrentSentenceIndex(-1);
      return;
    }

    const utterance = new SpeechSynthesisUtterance(queue[index]);
    utterance.rate = 1.0;
    utterance.pitch = 1.0;

    utterance.onstart = () => {
      setCurrentSentenceIndex(index);
    };

    utterance.onend = () => {
      speakSentence(index + 1, queue);
    };

    utterance.onerror = (e) => {
      console.error("Speech error", e);
      setIsSpeaking(false);
      setCurrentSentenceIndex(-1);
    };

    window.speechSynthesis.speak(utterance);
  };

  const handleSpeak = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setCurrentSentenceIndex(-1);
      return;
    }

    const articleEl = document.getElementById('article-content-body');
    const summaryEl = document.getElementById('ai-summary-content');

    let textToRead = "";

    // Prioritize or include AI summary if visible
    if (summaryEl) {
      textToRead += "AI Summary: " + summaryEl.innerText + ". ";
    }

    if (articleEl) {
      textToRead += articleEl.innerText;
    }

    if (!textToRead.trim()) {
      textToRead = isHome ? "Welcome to AccessiMod. Enter a topic to begin." : "";
    }

    if (!textToRead.trim()) return;

    // Split text into sentences using regex to create the queue
    const sentences = textToRead
      .match(/[^.!?]+[.!?]+/g)
      ?.map(s => s.trim())
      .filter(s => s.length > 0) || [textToRead.trim()];

    if (sentences.length > 0) {
      setIsSpeaking(true);
      setSpeechQueue(sentences);
      window.speechSynthesis.cancel(); // Clear any pending speech
      speakSentence(0, sentences);
    }
  };

  const updateSettings = async (newSettings: Partial<AccessibilitySettings>) => {
    if ('complexityLevel' in newSettings && newSettings.complexityLevel !== settings.complexityLevel) {
      const level = newSettings.complexityLevel!;
      if (complexityCache.current[level]) {
        setPageContent(prev => ({ ...prev, contentHtml: complexityCache.current[level] }));
        setSettings(prev => ({ ...prev, complexityLevel: level }));
      } else if (!isHome) {
        setIsRewriting(true);
        setApiError(null);
        const originalText = complexityCache.current[2] || pageContent.contentHtml;
        const result = await rewriteContent(originalText, level);
        if (result === "QUOTA_EXCEEDED") {
          setApiError("AI Limit Reached");
        } else {
          complexityCache.current[level] = result;
          setPageContent(prev => ({ ...prev, contentHtml: result }));
          setSettings(prev => ({ ...prev, complexityLevel: level }));
        }
        setIsRewriting(false);
      } else {
        setSettings(prev => ({ ...prev, complexityLevel: level }));
      }
      return;
    }

    setSettings(prev => {
      const next = { ...prev, ...newSettings };
      if (newSettings.mode) {
        if (newSettings.mode === 'reading') {
          next.readerMode = true;
          if (isHome) setTimeout(() => handleNavigate("Latest Accessibility News"), 100);
        } else {
          next.focusMode = newSettings.mode === 'adhd';
        }
        switch (newSettings.mode) {
          case 'dyslexia': next.lineSpacing = 1.8; next.fontWeight = 500; break;
          case 'adhd': next.lineSpacing = 1.8; next.fontSize = 20; next.stopAnimations = true; next.focusMode = true; break;
          case 'high-contrast': next.fontSize = 22; next.fontWeight = 700; next.highlightLinks = true; break;
          case 'default': next.fontSize = 18; next.fontWeight = 400; next.lineSpacing = 1.6; next.highlightLinks = false; next.focusMode = false; break;
        }
      }
      return next;
    });
  };

  const handleSendMessage = async (text: string) => {
    const userMsg: ChatMessage = { role: 'user', text };
    setChatMessages(prev => [...prev, userMsg]);
    setIsChatLoading(true);
    setApiError(null);
    const context = document.getElementById('article-content-body')?.innerText || "";
    const responseText = await askPageQuestion(context, text);
    setChatMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsChatLoading(false);
  };

  const handleSimplify = async () => {
    if (simplifiedContent) { setSimplifiedContent(null); return; }
    const articleEl = document.getElementById('article-content-body');
    if (!articleEl?.innerText) return;
    setIsSimplifying(true);
    setApiError(null);
    try {
      const result = await simplifyContent(articleEl.innerText);
      if (result === "QUOTA_EXCEEDED") setApiError("AI Limit Reached");
      else setSimplifiedContent(result as SimplifiedContentResponse);
    } finally { setIsSimplifying(false); }
  };

  const handleGenerateQuiz = async () => {
    if (quiz) { setQuiz(null); return; }
    const articleEl = document.getElementById('article-content-body');
    if (!articleEl?.innerText) return;
    setIsGeneratingQuiz(true);
    setApiError(null);
    try {
      const result = await generateQuiz(articleEl.innerText);
      if (result === "QUOTA_EXCEEDED") setApiError("AI Limit Reached");
      else setQuiz(result as QuizQuestion[]);
    } finally { setIsGeneratingQuiz(false); }
  };

  const handleNavigate = async (query: string) => {
    const q = query.trim();
    if (!q || q === "Home" || q.toLowerCase() === "accessimod") {
      setPageContent({ title: "AccessiMod", contentHtml: "" });
      complexityCache.current = {};
      setChatMessages([]);
      setSimplifiedContent(null);
      setQuiz(null);
      setSettings(prev => ({ ...prev, focusMode: false, readerMode: false, mode: 'default', complexityLevel: 2 }));
      return;
    }
    if (pageContent.title !== 'AccessiMod') setHistory(prev => [...prev, pageContent]);
    setIsLoadingPage(true);
    setChatMessages([]);
    setSimplifiedContent(null);
    setQuiz(null);
    setApiError(null);
    complexityCache.current = {}; 
    try {
      const content = await generatePageContent(q);
      if (content === "QUOTA_EXCEEDED") setApiError("AI Limit Reached");
      else {
        const data = content as WebPageContent;
        setPageContent(data);
        complexityCache.current[2] = data.contentHtml;
        setSettings(prev => ({ ...prev, complexityLevel: 2 }));
      }
    } finally { setIsLoadingPage(false); }
  };

  const handleBack = () => {
    if (history.length === 0) { if (!isHome) handleNavigate("Home"); return; }
    const newHistory = [...history];
    const prev = newHistory.pop();
    if (prev) { 
      setHistory(newHistory); 
      setPageContent(prev); 
      setChatMessages([]); 
      setSimplifiedContent(null); 
      setQuiz(null);
      setApiError(null);
      complexityCache.current = { 2: prev.contentHtml };
      setSettings(prevSet => ({ ...prevSet, complexityLevel: 2 }));
    }
  };

  const wrapperClasses = [
    "relative font-sans antialiased text-slate-900 dark:text-slate-100 transition-colors min-h-screen",
    settings.mode === 'dyslexia' ? 'dyslexia-mode' : '',
    settings.focusMode ? 'focus-mode-active' : '',
    settings.mode === 'high-contrast' ? 'high-contrast-mode' : ''
  ].join(' ');

  return (
    <div className={wrapperClasses}>
      <ControlPanel 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)}
        settings={settings} updateSettings={updateSettings}
        onSpeak={handleSpeak} isSpeaking={isSpeaking}
        onSimplify={handleSimplify} isSimplifying={isSimplifying}
        onGenerateQuiz={handleGenerateQuiz} isGeneratingQuiz={isGeneratingQuiz}
        isHome={isHome}
      />
      <SimulatedPage 
        settings={settings} simplifiedContent={simplifiedContent}
        content={pageContent} onNavigate={handleNavigate}
        onBack={handleBack} canGoBack={!isHome}
        isLoading={isLoadingPage} quiz={quiz}
        onToggleSettings={() => setIsSettingsOpen(!isSettingsOpen)}
        isDarkMode={isDarkMode} toggleTheme={toggleTheme}
        chatMessages={chatMessages} onSendMessage={handleSendMessage}
        isChatLoading={isChatLoading}
        isRewriting={isRewriting}
        apiError={apiError}
      />
    </div>
  );
};

