                  </button>
                </form>
              </div>
            )}
            <button 
              onClick={() => setIsChatOpen(!isChatOpen)} 
              className={`p-4 sm:p-5 rounded-full shadow-2xl transition-all active:scale-90 flex items-center justify-center ${isChatOpen ? 'bg-rose-500 text-white' : (isHighContrast ? 'bg-[#ffff00] text-black shadow-[#ffff00]/20' : 'bg-indigo-600 text-white hover:bg-indigo-700')}`}
            >
              {isChatOpen ? <X size={24} className="sm:w-7 sm:h-7" /> : <MessageCircle size={24} className="sm:w-7 sm:h-7" />}
