        .dyslexia-mode {
          background-color: #FFFDD0 !important;
          color: #222222 !important;
        }

        /* Ensure the entire app wrapper also takes the color */
        body:has(.dyslexia-mode) {
          background-color: #FFFDD0 !important;
        }

        .dyslexia-mode * { 
          font-family: 'Comic Sans MS', 'Verdana', sans-serif !important; 
          font-weight: 500 !important; 
          line-height: 1.8 !important; 
          letter-spacing: 0.03em !important; 
          word-spacing: 0.1em !important; 
          text-align: left !important;
        }

        .dyslexia-mode h1, 
        .dyslexia-mode h2, 
        .dyslexia-mode h3 {
          letter-spacing: 0.01em !important;
          margin-bottom: 0.5em !important;
          line-height: 1.3 !important;
          color: #111111 !important;
        }

        .dyslexia-mode p, 
        .dyslexia-mode div, 
        .dyslexia-mode li {
          max-width: 70ch !important;
          margin-bottom: 1.5em !important;
        }

        .dyslexia-mode h1 { font-size: clamp(2rem, 5vw, 3.5rem) !important; }
        .dyslexia-mode h2 { font-size: clamp(1.5rem, 4vw, 2.5rem) !important; }

        /* Remove "card" shadow and borders in Dyslexia Mode for true fullscreen appearance */
        .dyslexia-mode .browser-window {
          max-width: none !important;
          height: 100vh !important;
          border-radius: 0 !important;
          border: none !important;
          box-shadow: none !important;
          margin: 0 !important;
        }

        /* --- END CALIBRATED DYSLEXIA MODE --- */

        .focus-mode-active #simulated-viewport p, .focus-mode-active #simulated-viewport h1, .focus-mode-active #simulated-viewport h2 {
          opacity: 0.25; filter: blur(3px); transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
        }
        .focus-mode-active #simulated-viewport p:hover, .focus-mode-active #simulated-viewport h1:hover {
          opacity: 1 !important; filter: blur(0) !important; transform: scale(1.02); z-index: 10;
        }
        .high-contrast-mode button { border: 2px solid #ffff00 !important; }
      `}</style>

      <div className={`browser-window w-full max-w-[1400px] flex flex-col rounded-none sm:rounded-[2.5rem] overflow-hidden shadow-[0_32px_64px_-16px_rgba(0,0,0,0.15)] bg-theme-surface border border-theme-border h-[100vh] sm:h-[94vh] relative transition-all duration-300 ${isDyslexia ? 'max-w-none rounded-none' : ''}`}>
        <BrowserHeader 
          currentTopic={content.title} 
          isLoading={isLoading} 
          canGoBack={canGoBack} 
          onBack={onBack} 
          onNavigate={onNavigate} 
          onHome={() => onNavigate("Home")} 
          onToggleSettings={onToggleSettings} 
          isDarkMode={isDarkMode} 
          toggleTheme={toggleTheme} 
        />

        <div 
          id="simulated-viewport" 
          className={`flex-1 overflow-y-auto relative custom-scrollbar min-h-0 ${isDyslexia ? 'dyslexia-mode' : ''}`} 
          style={{ backgroundColor: isDyslexia ? '#FFFDD0' : styleVars['--bg-color'] }}
        >
          {apiError && (
