              )}

              <article 
                id="article-content" 
                className={`overflow-visible ${isDyslexia ? 'dyslexia-mode' : ''}`}
                style={{ 
                  color: isDyslexia ? '#222222' : styleVars['--text-color'], 
                  fontSize: isDyslexia ? '1.15rem' : styleVars['--font-size'], 
                  lineHeight: isDyslexia ? '1.8' : styleVars['--line-height'], 
