      {[...Array(12)].map((_, i) => (
        <div 
          key={i} 
          className={`h-5 rounded-lg ${highContrast ? 'bg-[#ffff00]/40' : 'bg-slate-100 dark:bg-slate-800'}`} 
          style={{ width: `${Math.floor(Math.random() * (100 - 60 + 1) + 60)}%`, animationDuration: '0.8s' }} 
        />
      ))}
    </div>
  </div>
);

